export interface TextLayer {
  id: string;
  content: string;
  x: number; // percentage 0-1 relative to container
  y: number; // percentage 0-1 relative to container
  color: string;
  backgroundColor: string; // 'transparent' or hex
  fontSize: number; // relative scale factor
  maxWidth?: number; // percentage 0-1, max width of the text box
  fontFamily: string;
  rotation: number;
}

export interface Size {
  width: number;
  height: number;
}

export interface Point {
  x: number;
  y: number;
}

export interface Stroke {
  points: Point[];
  color: string;
  size: number;
  opacity: number;
}

export const COLORS = [
  '#FFFFFF', // White
  '#000000', // Black
  '#EF4444', // Red
  '#F97316', // Orange
  '#EAB308', // Yellow
  '#22C55E', // Green
  '#3B82F6', // Blue
  '#A855F7', // Purple
  '#EC4899', // Pink
];

export const FONTS = [
  'font-sans',
  'font-serif',
  'font-mono',
  'font-anton',
  'font-bebas',
  'font-lobster',
  'font-oswald',
  'font-poppins',
];

export const FONT_FAMILY_MAP: Record<string, string> = {
  'font-sans': 'Inter, sans-serif',
  'font-serif': 'Merriweather, serif',
  'font-mono': '"JetBrains Mono", monospace',
  'font-anton': 'Anton, sans-serif',
  'font-bebas': '"Bebas Neue", sans-serif',
  'font-lobster': 'Lobster, cursive',
  'font-oswald': 'Oswald, sans-serif',
  'font-poppins': 'Poppins, sans-serif',
};

import React, { useRef, useEffect, useState } from 'react';
import { Stroke, Point } from '../types';

interface DrawingCanvasProps {
  width: number;
  height: number;
  isDrawingMode: boolean;
  currentColor: string;
  currentSize: number;
  currentOpacity: number;
  strokes: Stroke[];
  onAddStroke: (stroke: Stroke) => void;
}

export const DrawingCanvas: React.FC<DrawingCanvasProps> = ({
  width,
  height,
  isDrawingMode,
  currentColor,
  currentSize,
  currentOpacity,
  strokes,
  onAddStroke,
}) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const [isDrawing, setIsDrawing] = useState(false);
  const currentStroke = useRef<Point[]>([]);

  // Helper to draw a smooth stroke using quadratic curves
  const drawSmoothStroke = (ctx: CanvasRenderingContext2D, stroke: Stroke) => {
    if (stroke.points.length === 0) return;

    ctx.save();
    ctx.beginPath();
    ctx.strokeStyle = stroke.color;
    ctx.lineWidth = stroke.size;
    ctx.globalAlpha = stroke.opacity;

    const points = stroke.points;
    const p0 = points[0];
    ctx.moveTo(p0.x * width, p0.y * height);

    if (points.length < 3) {
      for (let i = 1; i < points.length; i++) {
        ctx.lineTo(points[i].x * width, points[i].y * height);
      }
    } else {
      let i;
      for (i = 1; i < points.length - 2; i++) {
        const xc = (points[i].x + points[i + 1].x) / 2;
        const yc = (points[i].y + points[i + 1].y) / 2;
        ctx.quadraticCurveTo(
          points[i].x * width,
          points[i].y * height,
          xc * width,
          yc * height
        );
      }
      ctx.quadraticCurveTo(
        points[i].x * width,
        points[i].y * height,
        points[i + 1].x * width,
        points[i + 1].y * height
      );
    }

    ctx.stroke();
    ctx.restore();
  };

  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;

    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    ctx.clearRect(0, 0, width, height);
    ctx.lineCap = 'round';
    ctx.lineJoin = 'round';

    strokes.forEach(stroke => {
      drawSmoothStroke(ctx, stroke);
    });
  }, [strokes, width, height]);

  const handlePointerDown = (e: React.PointerEvent) => {
    if (!isDrawingMode) return;
    e.preventDefault();
    e.stopPropagation();

    setIsDrawing(true);
    const rect = e.currentTarget.getBoundingClientRect();
    const x = (e.clientX - rect.left) / width;
    const y = (e.clientY - rect.top) / height;

    currentStroke.current = [{ x, y }];
    (e.target as Element).setPointerCapture(e.pointerId);
  };

  const handlePointerMove = (e: React.PointerEvent) => {
    if (!isDrawing || !isDrawingMode) return;
    e.preventDefault();
    e.stopPropagation();

    const rect = e.currentTarget.getBoundingClientRect();
    const x = (e.clientX - rect.left) / width;
    const y = (e.clientY - rect.top) / height;

    const lastPoint = currentStroke.current[currentStroke.current.length - 1];
    const dx = (x - lastPoint.x) * width;
    const dy = (y - lastPoint.y) * height;
    if (dx * dx + dy * dy < 25) return;

    currentStroke.current.push({ x, y });

    const ctx = canvasRef.current?.getContext('2d');
    if (ctx && currentStroke.current.length > 1) {
        ctx.save();
        ctx.beginPath();
        ctx.strokeStyle = currentColor;
        ctx.lineWidth = currentSize;
        ctx.globalAlpha = currentOpacity;
        ctx.lineCap = 'round';
        ctx.lineJoin = 'round';

        const prev = currentStroke.current[currentStroke.current.length - 2];
        ctx.moveTo(prev.x * width, prev.y * height);
        ctx.lineTo(x * width, y * height);
        ctx.stroke();
        ctx.restore();
    }
  };

  const handlePointerUp = (e: React.PointerEvent) => {
    if (!isDrawing) return;
    setIsDrawing(false);
    (e.target as Element).releasePointerCapture(e.pointerId);

    if (currentStroke.current.length > 0) {
      onAddStroke({
        points: [...currentStroke.current],
        color: currentColor,
        size: currentSize,
        opacity: currentOpacity
      });
    }
    currentStroke.current = [];
  };

  return (
    <canvas
      ref={canvasRef}
      width={width}
      height={height}
      className={`absolute inset-0 z-0 ${isDrawingMode ? 'cursor-crosshair touch-none' : 'pointer-events-none'}`}
      onPointerDown={handlePointerDown}
      onPointerMove={handlePointerMove}
      onPointerUp={handlePointerUp}
    />
  );
};

import React, { useState, useEffect } from 'react';
import { TextLayer, Stroke } from '../types';
import { TextOverlay } from './TextOverlay';
import { DrawingCanvas } from './DrawingCanvas';

interface EditorProps {
  images: string[];
  layers: TextLayer[];
  selectedId: string | null;
  strokes: Stroke[];
  isDrawing: boolean;
  drawingColor: string;
  drawingSize: number;
  drawingOpacity: number;
  onSelectLayer: (id: string | null) => void;
  onUpdateLayer: (id: string, updates: Partial<TextLayer>) => void;
  onDeleteLayer: (id: string) => void;
  onAddStroke: (stroke: Stroke) => void;
  containerRef: React.RefObject<HTMLDivElement>;
  children?: React.ReactNode;
}

export const Editor: React.FC<EditorProps> = ({
  images,
  layers,
  selectedId,
  strokes,
  isDrawing,
  drawingColor,
  drawingSize,
  drawingOpacity,
  onSelectLayer,
  onUpdateLayer,
  onDeleteLayer,
  onAddStroke,
  containerRef,
  children
}) => {
  const [containerSize, setContainerSize] = useState({ width: 0, height: 0 });

  useEffect(() => {
    if (!containerRef.current) return;

    const updateSize = () => {
      if (containerRef.current) {
        const { clientWidth, clientHeight } = containerRef.current;
        setContainerSize({ width: clientWidth, height: clientHeight });
      }
    };

    const resizeObserver = new ResizeObserver(updateSize);
    resizeObserver.observe(containerRef.current);
    updateSize();

    return () => resizeObserver.disconnect();
  }, [containerRef, images]);

  const handleBackgroundClick = () => {
    onSelectLayer(null);
  };

  const isMultiImage = images.length > 1;

  return (
    <div 
      className="flex-1 relative overflow-hidden flex items-center justify-center bg-black/90 p-4 md:p-8"
      onClick={handleBackgroundClick}
    >
      <div 
        ref={containerRef}
        className="relative shadow-2xl overflow-hidden inline-flex justify-center bg-black"
        style={{ 
          maxWidth: '100%',
          maxHeight: '80vh',
        }}
      >
        {images.map((src, index) => (
          <img
            key={index}
            src={src}
            alt={`Editable layer ${index + 1}`}
            className="object-contain block select-none pointer-events-none"
            style={{
              height: isMultiImage ? '60vh' : 'auto',
              maxHeight: isMultiImage ? 'none' : '80vh',
              maxWidth: '100%',
              width: 'auto'
            }}
          />
        ))}

        {/* Drawing Layer - sits between image and text */}
        <DrawingCanvas
            width={containerSize.width}
            height={containerSize.height}
            isDrawingMode={isDrawing}
            currentColor={drawingColor}
            currentSize={drawingSize}
            currentOpacity={drawingOpacity}
            strokes={strokes}
            onAddStroke={onAddStroke}
        />

        {/* Text Layers */}
        <div className={isDrawing ? 'pointer-events-none opacity-50 transition-opacity' : 'pointer-events-auto transition-opacity'}>
            {layers.map(layer => (
            <TextOverlay
                key={layer.id}
                layer={layer}
                isSelected={selectedId === layer.id}
                containerSize={containerSize}
                onSelect={onSelectLayer}
                onUpdate={onUpdateLayer}
                onDelete={onDeleteLayer}
            />
            ))}
        </div>

        {children}
      </div>
    </div>
  );
};

import React, { useState, useRef } from 'react';
import { Upload, Plus, Download, Wand2, Type, Trash2, RefreshCw, Pen, Palette, Circle, Highlighter } from 'lucide-react';
import { Editor } from './components/Editor';
import { TextLayer, Stroke, FONT_FAMILY_MAP, COLORS } from './types';
import { generateSmartCaption } from './services/gemini';
import { FloatingToolbar } from './components/FloatingToolbar';

export default function App() {
  const [images, setImages] = useState<string[]>([]);
  const [layers, setLayers] = useState<TextLayer[]>([]);
  const [strokes, setStrokes] = useState<Stroke[]>([]);
  const [selectedId, setSelectedId] = useState<string | null>(null);
  const [isProcessingAI, setIsProcessingAI] = useState(false);

  // Drawing State
  const [isDrawing, setIsDrawing] = useState(false);
  const [drawingTool, setDrawingTool] = useState<'pen' | 'highlighter'>('pen');
  const [drawingColor, setDrawingColor] = useState('#EF4444');
  const [drawingSize, setDrawingSize] = useState(5);

  const containerRef = useRef<HTMLDivElement>(null);

  // --- Actions ---

  const handleImageUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onload = (event) => {
        const result = event.target?.result as string;
        setImages(prev => {
          if (prev.length === 0) return [result];
          if (prev.length === 1) return [...prev, result];
          return [prev[0], result];
        });

        if (images.length === 0) {
            setLayers([]);
            setStrokes([]);
        }
      };
      reader.readAsDataURL(file);
    }
  };

  const handleReset = () => {
    setImages([]);
    setLayers([]);
    setStrokes([]);
    setSelectedId(null);
    setIsDrawing(false);
  };

  const addTextLayer = (initialText = "Tap to edit") => {
    if (isDrawing) setIsDrawing(false);

    const newLayer: TextLayer = {
      id: crypto.randomUUID(),
      content: initialText,
      x: 0.5,
      y: 0.5,
      color: '#FFFFFF',
      backgroundColor: 'transparent',
      fontSize: 1.0,
      fontFamily: 'font-anton',
      rotation: 0,
    };
    setLayers((prev) => [...prev, newLayer]);
    setSelectedId(newLayer.id);
  };

  const updateLayer = (id: string, updates: Partial<TextLayer>) => {
    setLayers((prev) =>
      prev.map((layer) => (layer.id === id ? { ...layer, ...updates } : layer))
    );
  };

  const deleteLayer = (id: string) => {
    setLayers((prev) => prev.filter((l) => l.id !== id));
    if (selectedId === id) setSelectedId(null);
  };

  const handleAddStroke = (stroke: Stroke) => {
    setStrokes(prev => [...prev, stroke]);
  };

  const handleSmartCaption = async () => {
    if (images.length === 0) return;
    setIsProcessingAI(true);
    try {
      const caption = await generateSmartCaption(images[0]);
      addTextLayer(caption);
    } catch (err) {
      alert("Failed to generate caption. Please check your API key or connection.");
    } finally {
      setIsProcessingAI(false);
    }
  };

  const loadImage = (src: string): Promise<HTMLImageElement> => {
    return new Promise((resolve, reject) => {
      const img = new Image();
      img.crossOrigin = "anonymous";
      img.onload = () => resolve(img);
      img.onerror = reject;
      img.src = src;
    });
  };

  const roundRect = (ctx: CanvasRenderingContext2D, x: number, y: number, width: number, height: number, radius: number) => {
    ctx.beginPath();
    ctx.moveTo(x + radius, y);
    ctx.lineTo(x + width - radius, y);
    ctx.quadraticCurveTo(x + width, y, x + width, y + radius);
    ctx.lineTo(x + width, y + height - radius);
    ctx.quadraticCurveTo(x + width, y + height, x + width - radius, y + height);
    ctx.lineTo(x + radius, y + height);
    ctx.quadraticCurveTo(x, y + height, x, y + height - radius);
    ctx.lineTo(x, y + radius);
    ctx.quadraticCurveTo(x, y, x + radius, y);
    ctx.closePath();
    ctx.fill();
  };

  const handleExport = async () => {
    if (images.length === 0) return;

    try {
        const canvas = document.createElement('canvas');
        const ctx = canvas.getContext('2d');
        if (!ctx) return;

        const loadedImages = await Promise.all(images.map(src => loadImage(src)));
        const img1 = loadedImages[0];

        let canvasWidth = img1.naturalWidth;
        const canvasHeight = img1.naturalHeight;

        let img2Specs: { img: HTMLImageElement, width: number, height: number, x: number } | null = null;

        if (loadedImages.length > 1) {
            const img2 = loadedImages[1];
            const scaleFactor = img1.naturalHeight / img2.naturalHeight;
            const scaledWidth = img2.naturalWidth * scaleFactor;

            img2Specs = {
                img: img2,
                width: scaledWidth,
                height: img1.naturalHeight,
                x: img1.naturalWidth
            };

            canvasWidth += scaledWidth;
        }

        canvas.width = canvasWidth;
        canvas.height = canvasHeight;

        ctx.drawImage(img1, 0, 0);
        if (img2Specs) {
            ctx.drawImage(img2Specs.img, img2Specs.x, 0, img2Specs.width, img2Specs.height);
        }

        ctx.lineCap = 'round';
        ctx.lineJoin = 'round';

        strokes.forEach(stroke => {
            if (stroke.points.length === 0) return;

            ctx.save();
            ctx.beginPath();
            ctx.strokeStyle = stroke.color;
            ctx.globalAlpha = stroke.opacity;
            const strokeScale = canvasWidth / (containerRef.current?.clientWidth || canvasWidth);
            ctx.lineWidth = stroke.size * strokeScale;

            const points = stroke.points;

            if (points.length < 3) {
                ctx.moveTo(points[0].x * canvasWidth, points[0].y * canvasHeight);
                for(let i=1; i<points.length; i++) {
                    ctx.lineTo(points[i].x * canvasWidth, points[i].y * canvasHeight);
                }
            } else {
                ctx.moveTo(points[0].x * canvasWidth, points[0].y * canvasHeight);
                let i;
                for (i = 1; i < points.length - 2; i++) {
                    const xc = (points[i].x + points[i + 1].x) / 2;
                    const yc = (points[i].y + points[i + 1].y) / 2;
                    ctx.quadraticCurveTo(
                        points[i].x * canvasWidth, 
                        points[i].y * canvasHeight, 
                        xc * canvasWidth, 
                        yc * canvasHeight
                    );
                }
                ctx.quadraticCurveTo(
                    points[i].x * canvasWidth, 
                    points[i].y * canvasHeight, 
                    points[i+1].x * canvasWidth, 
                    points[i+1].y * canvasHeight
                );
            }

            ctx.stroke();
            ctx.restore();
        });

        layers.forEach((layer) => {
            const fontSizePx = (canvasWidth / 20) * layer.fontSize;

            ctx.save();
            const x = layer.x * canvasWidth;
            const y = layer.y * canvasHeight;

            ctx.translate(x, y);
            ctx.rotate((layer.rotation * Math.PI) / 180);

            let fontFamily = FONT_FAMILY_MAP[layer.fontFamily] || 'sans-serif';
            fontFamily = fontFamily.replace(/"/g, ''); 

            ctx.font = `bold ${fontSizePx}px ${fontFamily}`;
            ctx.textAlign = 'center';
            ctx.textBaseline = 'middle';

            let lines = layer.content.split('\n');
            if (layer.maxWidth) {
                const maxPx = layer.maxWidth * canvasWidth;
                const wrappedLines: string[] = [];
                lines.forEach(paragraph => {
                    const words = paragraph.split(' ');
                    let currentLine = words[0];
                    for (let i = 1; i < words.length; i++) {
                        const word = words[i];
                        const width = ctx.measureText(currentLine + " " + word).width;
                        if (width < maxPx) {
                            currentLine += " " + word;
                        } else {
                            wrappedLines.push(currentLine);
                            currentLine = word;
                        }
                    }
                    wrappedLines.push(currentLine);
                });
                lines = wrappedLines;
            }

            const lineHeight = fontSizePx * 1.2;
            const totalHeight = lines.length * lineHeight;

            let maxLineWidth = 0;
            lines.forEach(line => {
                const metrics = ctx.measureText(line);
                if (metrics.width > maxLineWidth) maxLineWidth = metrics.width;
            });

            if (layer.backgroundColor !== 'transparent') {
                const paddingX = fontSizePx * 0.4;
                const paddingY = fontSizePx * 0.2;
                const bgWidth = maxLineWidth + (paddingX * 2);
                const bgHeight = totalHeight + (paddingY * 2);

                ctx.fillStyle = layer.backgroundColor;
                roundRect(
                    ctx, 
                    -bgWidth / 2, 
                    -bgHeight / 2, 
                    bgWidth, 
                    bgHeight, 
                    fontSizePx * 0.2
                );
            } else {
                ctx.shadowColor = 'rgba(0, 0, 0, 0.5)';
                ctx.shadowBlur = 4;
                ctx.shadowOffsetY = 2;
            }

            ctx.fillStyle = layer.color;
            if (layer.backgroundColor !== 'transparent') {
                 ctx.shadowColor = 'transparent';
            }

            let startY = -(totalHeight / 2) + (lineHeight / 2);
            lines.forEach((line, i) => {
                ctx.fillText(line, 0, startY + (i * lineHeight));
            });

            ctx.restore();
        });

        const link = document.createElement('a');
        link.download = `snaptext-${Date.now()}.png`;
        link.href = canvas.toDataURL('image/png');
        link.click();

    } catch (e) {
        console.error("Export failed", e);
        alert("Failed to export image.");
    }
  };

  const currentOpacity = drawingTool === 'highlighter' ? 0.45 : 1.0;
  const displayDrawingSize = drawingTool === 'highlighter' ? drawingSize * 3 : drawingSize;

  if (images.length === 0) {
    return (
      <div className="h-screen w-full flex flex-col items-center justify-center bg-slate-900 text-white p-6 relative overflow-hidden">
        <div className="absolute top-[-10%] left-[-10%] w-[40%] h-[40%] bg-purple-600 rounded-full blur-[120px] opacity-20"></div>
        <div className="absolute bottom-[-10%] right-[-10%] w-[40%] h-[40%] bg-blue-600 rounded-full blur-[120px] opacity-20"></div>

        <div className="z-10 text-center max-w-md">
          <div className="mb-6 flex justify-center">
            <div className="w-20 h-20 bg-gradient-to-tr from-purple-500 to-pink-500 rounded-2xl flex items-center justify-center shadow-lg transform rotate-3">
               <Type size={40} className="text-white" />
            </div>
          </div>
          <h1 className="text-4xl font-extrabold mb-4 tracking-tight">SnapText Editor</h1>
          <p className="text-slate-400 mb-8 text-lg">
            Add bold, beautiful text to your photos. Messenger-style editing with side-by-side support.
          </p>

          <label className="group relative inline-flex items-center justify-center px-8 py-4 text-lg font-bold text-white transition-all duration-200 bg-blue-600 font-pj rounded-full focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-blue-600 hover:bg-blue-500 cursor-pointer shadow-lg shadow-blue-500/30">
            <span className="absolute inset-0 transition-transform translate-x-1 translate-y-1 bg-blue-700 group-hover:translate-y-0 group-hover:translate-x-0 rounded-full"></span>
            <span className="relative flex items-center gap-2">
              <Upload size={24} />
              <span>Choose Photo</span>
            </span>
            <input type="file" accept="image/*" onChange={handleImageUpload} className="hidden" />
          </label>
        </div>
      </div>
    );
  }

  const selectedLayer = layers.find(l => l.id === selectedId);

  return (
    <div className="h-screen w-full flex flex-col bg-slate-950 text-white overflow-hidden relative">
      <header className="h-16 px-4 flex items-center justify-between border-b border-slate-800 bg-slate-900/50 backdrop-blur-md z-40">
        <div className="flex items-center gap-2 font-bold text-xl tracking-tight">
          <span className="text-blue-500">Snap</span>Text
        </div>
        <div className="flex gap-3">
          {images.length < 2 && (
            <label className="flex items-center gap-2 px-3 py-2 bg-slate-800 hover:bg-slate-700 text-slate-200 rounded-full text-sm font-medium transition-colors cursor-pointer border border-slate-700">
               <Plus size={16} />
               <span>Add Photo</span>
               <input type="file" accept="image/*" onChange={handleImageUpload} className="hidden" />
            </label>
          )}
          <button 
            onClick={handleExport}
            className="flex items-center gap-2 px-4 py-2 bg-blue-600 hover:bg-blue-500 text-white rounded-full text-sm font-semibold transition-all shadow-md shadow-blue-500/20"
          >
            <Download size={16} />
            Save
          </button>
        </div>
      </header>

      <Editor
        images={images}
        layers={layers}
        selectedId={selectedId}
        strokes={strokes}
        isDrawing={isDrawing}
        drawingColor={drawingColor}
        drawingSize={displayDrawingSize}
        drawingOpacity={currentOpacity}
        onSelectLayer={setSelectedId}
        onUpdateLayer={updateLayer}
        onDeleteLayer={deleteLayer}
        onAddStroke={handleAddStroke}
        containerRef={containerRef}
      >
        {!selectedId && (
            <div className="absolute top-4 right-4 z-[60] flex flex-col gap-4">
                <button 
                  onClick={() => addTextLayer()}
                  className={`flex flex-col items-center gap-1 group ${isDrawing ? 'opacity-50' : ''}`}
                  title="Add Text"
                >
                    <div className="w-10 h-10 bg-slate-900/60 backdrop-blur-md border border-white/10 rounded-full flex items-center justify-center shadow-lg hover:bg-slate-800 text-white transition-all transform group-hover:scale-105">
                        <Type size={20} />
                    </div>
                    <span className="text-[10px] font-semibold text-white/90 drop-shadow-md">Text</span>
                </button>

                <button 
                  onClick={() => {
                    setIsDrawing(!isDrawing);
                    setSelectedId(null);
                  }}
                  className={`flex flex-col items-center gap-1 group`}
                  title="Draw"
                >
                    <div className={`w-10 h-10 backdrop-blur-md border border-white/10 rounded-full flex items-center justify-center shadow-lg text-white transition-all transform group-hover:scale-105 ${isDrawing ? 'bg-blue-600 border-blue-400' : 'bg-slate-900/60 hover:bg-slate-800'}`}>
                        {drawingTool === 'pen' ? <Pen size={18} /> : <Highlighter size={18} />}
                    </div>
                    <span className="text-[10px] font-semibold text-white/90 drop-shadow-md">Draw</span>
                </button>

                <button 
                  onClick={handleSmartCaption}
                  disabled={isProcessingAI}
                  className={`flex flex-col items-center gap-1 group disabled:opacity-50 ${isDrawing ? 'opacity-50' : ''}`}
                  title="Magic Caption"
                >
                    <div className="w-10 h-10 bg-gradient-to-tr from-purple-600/80 to-blue-600/80 backdrop-blur-md border border-white/10 rounded-full flex items-center justify-center shadow-lg hover:brightness-110 text-white transition-all transform group-hover:scale-105">
                        {isProcessingAI ? <div className="w-4 h-4 border-2 border-white/50 border-t-white rounded-full animate-spin" /> : <Wand2 size={20} />}
                    </div>
                    <span className="text-[10px] font-semibold text-white/90 drop-shadow-md">Magic</span>
                </button>

                <button 
                  onClick={handleReset}
                  className="flex flex-col items-center gap-1 group"
                  title="Reset All"
                >
                    <div className="w-10 h-10 bg-slate-900/60 backdrop-blur-md border border-white/10 rounded-full flex items-center justify-center shadow-lg hover:bg-red-500/80 text-white transition-all transform group-hover:scale-105">
                        <RefreshCw size={18} />
                    </div>
                    <span className="text-[10px] font-semibold text-white/90 drop-shadow-md">Reset</span>
                </button>
            </div>
        )}

        {isDrawing && !selectedId && (
            <div className="absolute bottom-6 left-1/2 -translate-x-1/2 flex items-center gap-2 p-2 bg-slate-900/80 backdrop-blur-md rounded-full border border-white/10 z-[60] animate-in slide-in-from-bottom-5">
                 <div className="flex gap-1 px-1 mr-1">
                    <button 
                        onClick={() => setDrawingTool('pen')}
                        className={`p-2 rounded-full transition-all ${drawingTool === 'pen' ? 'bg-white text-black' : 'text-white hover:bg-white/10'}`}
                        title="Pen"
                    >
                        <Pen size={16} />
                    </button>
                    <button 
                        onClick={() => setDrawingTool('highlighter')}
                        className={`p-2 rounded-full transition-all ${drawingTool === 'highlighter' ? 'bg-white text-black' : 'text-white hover:bg-white/10'}`}
                        title="Highlighter"
                    >
                        <Highlighter size={16} />
                    </button>
                 </div>
                 <div className="w-[1px] h-6 bg-white/20 mx-1"></div>
                 <div className="flex gap-2 px-2">
                    {COLORS.map(color => (
                        <button
                            key={color}
                            className={`w-6 h-6 rounded-full border-2 transition-transform ${drawingColor === color ? 'border-white scale-110' : 'border-transparent hover:scale-105'}`}
                            style={{ backgroundColor: color }}
                            onClick={() => setDrawingColor(color)}
                        />
                    ))}
                 </div>
                 <div className="w-[1px] h-6 bg-white/20 mx-1"></div>
                 <div className="flex gap-2 px-2 items-center">
                    <button onClick={() => setDrawingSize(Math.max(2, drawingSize - 2))} className="p-1 hover:text-blue-400"><Circle size={8} fill="currentColor" /></button>
                    <span className="text-xs w-4 text-center">{drawingSize}</span>
                    <button onClick={() => setDrawingSize(Math.min(20, drawingSize + 2))} className="p-1 hover:text-blue-400"><Circle size={16} fill="currentColor" /></button>
                 </div>
                 <div className="w-[1px] h-6 bg-white/20 mx-1"></div>
                 <button 
                    onClick={() => setStrokes([])}
                    className="p-1.5 text-white/70 hover:text-red-400 transition-colors"
                    title="Clear Drawing"
                 >
                     <Trash2 size={16} />
                 </button>
            </div>
        )}
      </Editor>

      {selectedId && selectedLayer && (
        <FloatingToolbar
          layer={selectedLayer}
          containerRef={containerRef}
          onUpdate={updateLayer}
          onDelete={deleteLayer}
          onClose={() => setSelectedId(null)}
        />
      )}
    </div>
  );
}

import React, { useState, useRef, useEffect, useCallback } from 'react';
import { Upload, Plus, Download, Wand2, Type, Trash2, RefreshCw, Pen, Palette, Circle, Highlighter, Undo2, Redo2 } from 'lucide-react';
import { Editor } from './components/Editor';
import { TextLayer, Stroke, FONT_FAMILY_MAP, COLORS } from './types';
import { generateSmartCaption } from './services/gemini';
import { FloatingToolbar } from './components/FloatingToolbar';

interface HistoryState {
  layers: TextLayer[];
  strokes: Stroke[];
}

export default function App() {
  const [images, setImages] = useState<string[]>([]);
  const [layers, setLayers] = useState<TextLayer[]>([]);
  const [strokes, setStrokes] = useState<Stroke[]>([]);
  const [selectedId, setSelectedId] = useState<string | null>(null);
  const [isProcessingAI, setIsProcessingAI] = useState(false);

  // History State
  const [history, setHistory] = useState<HistoryState[]>([]);
  const [historyIndex, setHistoryIndex] = useState(-1);

  // Drawing State
  const [isDrawing, setIsDrawing] = useState(false);
  const [drawingTool, setDrawingTool] = useState<'pen' | 'highlighter'>('pen');
  const [drawingColor, setDrawingColor] = useState('#EF4444');
  const [drawingSize, setDrawingSize] = useState(5);

  const containerRef = useRef<HTMLDivElement>(null);

  // --- History Management ---

  const pushToHistory = useCallback((newLayers: TextLayer[], newStrokes: Stroke[]) => {
    setHistory(prev => {
      const newHistory = prev.slice(0, historyIndex + 1);
      const nextState = { layers: JSON.parse(JSON.stringify(newLayers)), strokes: JSON.parse(JSON.stringify(newStrokes)) };

      // Don't push identical state
      if (newHistory.length > 0) {
        const last = newHistory[newHistory.length - 1];
        if (JSON.stringify(last) === JSON.stringify(nextState)) return prev;
      }

      const updated = [...newHistory, nextState];
      // Limit history to 50 steps
      if (updated.length > 50) updated.shift();
      return updated;
    });
    setHistoryIndex(prev => {
      const newIdx = prev + 1;
      return Math.min(newIdx, 49); // Adjust based on shift
    });
  }, [historyIndex]);

  const undo = () => {
    if (historyIndex > 0) {
      const prevIdx = historyIndex - 1;
      const state = history[prevIdx];
      setLayers(state.layers);
      setStrokes(state.strokes);
      setHistoryIndex(prevIdx);
      setSelectedId(null);
    }
  };

  const redo = () => {
    if (historyIndex < history.length - 1) {
      const nextIdx = historyIndex + 1;
      const state = history[nextIdx];
      setLayers(state.layers);
      setStrokes(state.strokes);
      setHistoryIndex(nextIdx);
      setSelectedId(null);
    }
  };

  // Initialize history on first load/reset
  useEffect(() => {
    if (images.length > 0 && history.length === 0) {
      setHistory([{ layers: [], strokes: [] }]);
      setHistoryIndex(0);
    }
  }, [images, history.length]);

  // --- Actions ---

  const handleImageUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onload = (event) => {
        const result = event.target?.result as string;
        setImages(prev => {
          if (prev.length === 0) return [result];
          if (prev.length === 1) return [...prev, result];
          return [prev[0], result];
        });

        if (images.length === 0) {
            setLayers([]);
            setStrokes([]);
            setHistory([{ layers: [], strokes: [] }]);
            setHistoryIndex(0);
        }
      };
      reader.readAsDataURL(file);
    }
  };

  const handleReset = () => {
    setImages([]);
    setLayers([]);
    setStrokes([]);
    setSelectedId(null);
    setIsDrawing(false);
    setHistory([]);
    setHistoryIndex(-1);
  };

  const addTextLayer = (initialText = "Tap to edit") => {
    if (isDrawing) setIsDrawing(false);

    const newLayer: TextLayer = {
      id: crypto.randomUUID(),
      content: initialText,
      x: 0.5,
      y: 0.5,
      color: '#FFFFFF',
      backgroundColor: 'transparent',
      fontSize: 1.0,
      fontFamily: 'font-anton',
      rotation: 0,
    };
    const nextLayers = [...layers, newLayer];
    setLayers(nextLayers);
    setSelectedId(newLayer.id);
    pushToHistory(nextLayers, strokes);
  };

  const updateLayer = (id: string, updates: Partial<TextLayer>, skipHistory = false) => {
    const nextLayers = layers.map((layer) => (layer.id === id ? { ...layer, ...updates } : layer));
    setLayers(nextLayers);
    if (!skipHistory) {
      pushToHistory(nextLayers, strokes);
    }
  };

  const deleteLayer = (id: string) => {
    const nextLayers = layers.filter((l) => l.id !== id);
    setLayers(nextLayers);
    if (selectedId === id) setSelectedId(null);
    pushToHistory(nextLayers, strokes);
  };

  const handleAddStroke = (stroke: Stroke) => {
    const nextStrokes = [...strokes, stroke];
    setStrokes(nextStrokes);
    pushToHistory(layers, nextStrokes);
  };

  const handleSmartCaption = async () => {
    if (images.length === 0) return;
    setIsProcessingAI(true);
    try {
      const caption = await generateSmartCaption(images[0]);
      addTextLayer(caption);
    } catch (err) {
      alert("Failed to generate caption. Please check your API key or connection.");
    } finally {
      setIsProcessingAI(false);
    }
  };

  const loadImage = (src: string): Promise<HTMLImageElement> => {
    return new Promise((resolve, reject) => {
      const img = new Image();
      img.crossOrigin = "anonymous";
      img.onload = () => resolve(img);
      img.onerror = reject;
      img.src = src;
    });
  };

  const roundRect = (ctx: CanvasRenderingContext2D, x: number, y: number, width: number, height: number, radius: number) => {
    ctx.beginPath();
    ctx.moveTo(x + radius, y);
    ctx.lineTo(x + width - radius, y);
    ctx.quadraticCurveTo(x + width, y, x + width, y + radius);
    ctx.lineTo(x + width, y + height - radius);
    ctx.quadraticCurveTo(x + width, y + height, x + width - radius, y + height);
    ctx.lineTo(x + radius, y + height);
    ctx.quadraticCurveTo(x, y + height, x, y + height - radius);
    ctx.lineTo(x, y + radius);
    ctx.quadraticCurveTo(x, y, x + radius, y);
    ctx.closePath();
    ctx.fill();
  };

  const handleExport = async () => {
    if (images.length === 0) return;

    try {
        const canvas = document.createElement('canvas');
        const ctx = canvas.getContext('2d');
        if (!ctx) return;

        const loadedImages = await Promise.all(images.map(src => loadImage(src)));
        const img1 = loadedImages[0];

        let canvasWidth = img1.naturalWidth;
        const canvasHeight = img1.naturalHeight;

        let img2Specs: { img: HTMLImageElement, width: number, height: number, x: number } | null = null;

        if (loadedImages.length > 1) {
            const img2 = loadedImages[1];
            const scaleFactor = img1.naturalHeight / img2.naturalHeight;
            const scaledWidth = img2.naturalWidth * scaleFactor;

            img2Specs = {
                img: img2,
                width: scaledWidth,
                height: img1.naturalHeight,
                x: img1.naturalWidth
            };

            canvasWidth += scaledWidth;
        }

        canvas.width = canvasWidth;
        canvas.height = canvasHeight;

        ctx.drawImage(img1, 0, 0);
        if (img2Specs) {
            ctx.drawImage(img2Specs.img, img2Specs.x, 0, img2Specs.width, img2Specs.height);
        }

        ctx.lineCap = 'round';
        ctx.lineJoin = 'round';

        strokes.forEach(stroke => {
            if (stroke.points.length === 0) return;

            ctx.save();
            ctx.beginPath();
            ctx.strokeStyle = stroke.color;
            ctx.globalAlpha = stroke.opacity;
            const strokeScale = canvasWidth / (containerRef.current?.clientWidth || canvasWidth);
            ctx.lineWidth = stroke.size * strokeScale;

            const points = stroke.points;

            if (points.length < 3) {
                ctx.moveTo(points[0].x * canvasWidth, points[0].y * canvasHeight);
                for(let i=1; i<points.length; i++) {
                    ctx.lineTo(points[i].x * canvasWidth, points[i].y * canvasHeight);
                }
            } else {
                ctx.moveTo(points[0].x * canvasWidth, points[0].y * canvasHeight);
                let i;
                for (i = 1; i < points.length - 2; i++) {
                    const xc = (points[i].x + points[i + 1].x) / 2;
                    const yc = (points[i].y + points[i + 1].y) / 2;
                    ctx.quadraticCurveTo(
                        points[i].x * canvasWidth, 
                        points[i].y * canvasHeight, 
                        xc * canvasWidth, 
                        yc * canvasHeight
                    );
                }
                ctx.quadraticCurveTo(
                    points[i].x * canvasWidth, 
                    points[i].y * canvasHeight, 
                    points[i+1].x * canvasWidth, 
                    points[i+1].y * canvasHeight
                );
            }

            ctx.stroke();
            ctx.restore();
        });

        layers.forEach((layer) => {
            const fontSizePx = (canvasWidth / 20) * layer.fontSize;

            ctx.save();
            const x = layer.x * canvasWidth;
            const y = layer.y * canvasHeight;

            ctx.translate(x, y);
            ctx.rotate((layer.rotation * Math.PI) / 180);

            let fontFamily = FONT_FAMILY_MAP[layer.fontFamily] || 'sans-serif';
            fontFamily = fontFamily.replace(/"/g, ''); 

            ctx.font = `bold ${fontSizePx}px ${fontFamily}`;
            ctx.textAlign = 'center';
            ctx.textBaseline = 'middle';

            let lines = layer.content.split('\n');
            if (layer.maxWidth) {
                const maxPx = layer.maxWidth * canvasWidth;
                const wrappedLines: string[] = [];
                lines.forEach(paragraph => {
                    const words = paragraph.split(' ');
                    let currentLine = words[0];
                    for (let i = 1; i < words.length; i++) {
                        const word = words[i];
                        const width = ctx.measureText(currentLine + " " + word).width;
                        if (width < maxPx) {
                            currentLine += " " + word;
                        } else {
                            wrappedLines.push(currentLine);
                            currentLine = word;
                        }
                    }
                    wrappedLines.push(currentLine);
                });
                lines = wrappedLines;
            }

            const lineHeight = fontSizePx * 1.2;
            const totalHeight = lines.length * lineHeight;

            let maxLineWidth = 0;
            lines.forEach(line => {
                const metrics = ctx.measureText(line);
                if (metrics.width > maxLineWidth) maxLineWidth = metrics.width;
            });

            if (layer.backgroundColor !== 'transparent') {
                const paddingX = fontSizePx * 0.4;
                const paddingY = fontSizePx * 0.2;
                const bgWidth = maxLineWidth + (paddingX * 2);
                const bgHeight = totalHeight + (paddingY * 2);

                ctx.fillStyle = layer.backgroundColor;
                roundRect(
                    ctx, 
                    -bgWidth / 2, 
                    -bgHeight / 2, 
                    bgWidth, 
                    bgHeight, 
                    fontSizePx * 0.2
                );
            } else {
                ctx.shadowColor = 'rgba(0, 0, 0, 0.5)';
                ctx.shadowBlur = 4;
                ctx.shadowOffsetY = 2;
            }

            ctx.fillStyle = layer.color;
            if (layer.backgroundColor !== 'transparent') {
                 ctx.shadowColor = 'transparent';
            }

            let startY = -(totalHeight / 2) + (lineHeight / 2);
            lines.forEach((line, i) => {
                ctx.fillText(line, 0, startY + (i * lineHeight));
            });

            ctx.restore();
        });

        const link = document.createElement('a');
        link.download = `snaptext-${Date.now()}.png`;
        link.href = canvas.toDataURL('image/png');
        link.click();

    } catch (e) {
        console.error("Export failed", e);
        alert("Failed to export image.");
    }
  };

  const currentOpacity = drawingTool === 'highlighter' ? 0.45 : 1.0;
  const displayDrawingSize = drawingTool === 'highlighter' ? drawingSize * 3 : drawingSize;

  if (images.length === 0) {
    return (
      <div className="h-screen w-full flex flex-col items-center justify-center bg-slate-900 text-white p-6 relative overflow-hidden">
        <div className="absolute top-[-10%] left-[-10%] w-[40%] h-[40%] bg-purple-600 rounded-full blur-[120px] opacity-20"></div>
        <div className="absolute bottom-[-10%] right-[-10%] w-[40%] h-[40%] bg-blue-600 rounded-full blur-[120px] opacity-20"></div>

        <div className="z-10 text-center max-w-md">
          <div className="mb-6 flex justify-center">
            <div className="w-20 h-20 bg-gradient-to-tr from-purple-500 to-pink-500 rounded-2xl flex items-center justify-center shadow-lg transform rotate-3">
               <Type size={40} className="text-white" />
            </div>
          </div>
          <h1 className="text-4xl font-extrabold mb-4 tracking-tight">SnapText Editor</h1>
          <p className="text-slate-400 mb-8 text-lg">
            Add bold, beautiful text to your photos. Messenger-style editing with side-by-side support.
          </p>

          <label className="group relative inline-flex items-center justify-center px-8 py-4 text-lg font-bold text-white transition-all duration-200 bg-blue-600 font-pj rounded-full focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-blue-600 hover:bg-blue-500 cursor-pointer shadow-lg shadow-blue-500/30">
            <span className="absolute inset-0 transition-transform translate-x-1 translate-y-1 bg-blue-700 group-hover:translate-y-0 group-hover:translate-x-0 rounded-full"></span>
            <span className="relative flex items-center gap-2">
              <Upload size={24} />
              <span>Choose Photo</span>
            </span>
            <input type="file" accept="image/*" onChange={handleImageUpload} className="hidden" />
          </label>
        </div>
      </div>
    );
  }

  const selectedLayer = layers.find(l => l.id === selectedId);

  return (
    <div className="h-screen w-full flex flex-col bg-slate-950 text-white overflow-hidden relative">
      <header className="h-16 px-4 flex items-center justify-between border-b border-slate-800 bg-slate-900/50 backdrop-blur-md z-40">
        <div className="flex items-center gap-2 font-bold text-xl tracking-tight">
          <span className="text-blue-500">Snap</span>Text
        </div>

        <div className="flex items-center gap-2">
          <button 
            onClick={undo}
            disabled={historyIndex <= 0}
            className="p-2 text-slate-300 hover:text-white disabled:opacity-30 disabled:cursor-not-allowed transition-all"
            title="Undo"
          >
            <Undo2 size={20} />
          </button>
          <button 
            onClick={redo}
            disabled={historyIndex >= history.length - 1}
            className="p-2 text-slate-300 hover:text-white disabled:opacity-30 disabled:cursor-not-allowed transition-all"
            title="Redo"
          >
            <Redo2 size={20} />
          </button>
        </div>

        <div className="flex gap-3">
          {images.length < 2 && (
            <label className="flex items-center gap-2 px-3 py-2 bg-slate-800 hover:bg-slate-700 text-slate-200 rounded-full text-sm font-medium transition-colors cursor-pointer border border-slate-700">
               <Plus size={16} />
               <span>Add Photo</span>
               <input type="file" accept="image/*" onChange={handleImageUpload} className="hidden" />
            </label>
          )}
          <button 
            onClick={handleExport}
            className="flex items-center gap-2 px-4 py-2 bg-blue-600 hover:bg-blue-500 text-white rounded-full text-sm font-semibold transition-all shadow-md shadow-blue-500/20"
          >
            <Download size={16} />
            Save
          </button>
        </div>
      </header>

      <Editor
        images={images}
        layers={layers}
        selectedId={selectedId}
        strokes={strokes}
        isDrawing={isDrawing}
        drawingColor={drawingColor}
        drawingSize={displayDrawingSize}
        drawingOpacity={currentOpacity}
        onSelectLayer={setSelectedId}
        onUpdateLayer={updateLayer}
        onDeleteLayer={deleteLayer}
        onAddStroke={handleAddStroke}
        containerRef={containerRef}
      >
        {!selectedId && (
            <div className="absolute top-4 right-4 z-[60] flex flex-col gap-4">
                <button 
                  onClick={() => addTextLayer()}
                  className={`flex flex-col items-center gap-1 group ${isDrawing ? 'opacity-50' : ''}`}
                  title="Add Text"
                >
                    <div className="w-10 h-10 bg-slate-900/60 backdrop-blur-md border border-white/10 rounded-full flex items-center justify-center shadow-lg hover:bg-slate-800 text-white transition-all transform group-hover:scale-105">
                        <Type size={20} />
                    </div>
                    <span className="text-[10px] font-semibold text-white/90 drop-shadow-md">Text</span>
                </button>

                <button 
                  onClick={() => {
                    setIsDrawing(!isDrawing);
                    setSelectedId(null);
                  }}
                  className={`flex flex-col items-center gap-1 group`}
                  title="Draw"
                >
                    <div className={`w-10 h-10 backdrop-blur-md border border-white/10 rounded-full flex items-center justify-center shadow-lg text-white transition-all transform group-hover:scale-105 ${isDrawing ? 'bg-blue-600 border-blue-400' : 'bg-slate-900/60 hover:bg-slate-800'}`}>
                        {drawingTool === 'pen' ? <Pen size={18} /> : <Highlighter size={18} />}
                    </div>
                    <span className="text-[10px] font-semibold text-white/90 drop-shadow-md">Draw</span>
                </button>

                <button 
                  onClick={handleSmartCaption}
                  disabled={isProcessingAI}
                  className={`flex flex-col items-center gap-1 group disabled:opacity-50 ${isDrawing ? 'opacity-50' : ''}`}
                  title="Magic Caption"
                >
                    <div className="w-10 h-10 bg-gradient-to-tr from-purple-600/80 to-blue-600/80 backdrop-blur-md border border-white/10 rounded-full flex items-center justify-center shadow-lg hover:brightness-110 text-white transition-all transform group-hover:scale-105">
                        {isProcessingAI ? <div className="w-4 h-4 border-2 border-white/50 border-t-white rounded-full animate-spin" /> : <Wand2 size={20} />}
                    </div>
                    <span className="text-[10px] font-semibold text-white/90 drop-shadow-md">Magic</span>
                </button>

                <button 
                  onClick={handleReset}
                  className="flex flex-col items-center gap-1 group"
                  title="Reset All"
                >
                    <div className="w-10 h-10 bg-slate-900/60 backdrop-blur-md border border-white/10 rounded-full flex items-center justify-center shadow-lg hover:bg-red-500/80 text-white transition-all transform group-hover:scale-105">
                        <RefreshCw size={18} />
                    </div>
                    <span className="text-[10px] font-semibold text-white/90 drop-shadow-md">Reset</span>
                </button>
            </div>
        )}

        {isDrawing && !selectedId && (
            <div className="absolute bottom-6 left-1/2 -translate-x-1/2 flex items-center gap-2 p-2 bg-slate-900/80 backdrop-blur-md rounded-full border border-white/10 z-[60] animate-in slide-in-from-bottom-5">
                 <div className="flex gap-1 px-1 mr-1">
                    <button 
                        onClick={() => setDrawingTool('pen')}
                        className={`p-2 rounded-full transition-all ${drawingTool === 'pen' ? 'bg-white text-black' : 'text-white hover:bg-white/10'}`}
                        title="Pen"
                    >
                        <Pen size={16} />
                    </button>
                    <button 
                        onClick={() => setDrawingTool('highlighter')}
                        className={`p-2 rounded-full transition-all ${drawingTool === 'highlighter' ? 'bg-white text-black' : 'text-white hover:bg-white/10'}`}
                        title="Highlighter"
                    >
                        <Highlighter size={16} />
                    </button>
                 </div>
                 <div className="w-[1px] h-6 bg-white/20 mx-1"></div>
                 <div className="flex gap-2 px-2">
                    {COLORS.map(color => (
                        <button
                            key={color}
                            className={`w-6 h-6 rounded-full border-2 transition-transform ${drawingColor === color ? 'border-white scale-110' : 'border-transparent hover:scale-105'}`}
                            style={{ backgroundColor: color }}
                            onClick={() => setDrawingColor(color)}
                        />
                    ))}
                 </div>
                 <div className="w-[1px] h-6 bg-white/20 mx-1"></div>
                 <div className="flex gap-2 px-2 items-center">
                    <button onClick={() => setDrawingSize(Math.max(2, drawingSize - 2))} className="p-1 hover:text-blue-400"><Circle size={8} fill="currentColor" /></button>
                    <span className="text-xs w-4 text-center">{drawingSize}</span>
                    <button onClick={() => setDrawingSize(Math.min(20, drawingSize + 2))} className="p-1 hover:text-blue-400"><Circle size={16} fill="currentColor" /></button>
                 </div>
                 <div className="w-[1px] h-6 bg-white/20 mx-1"></div>
                 <button 
                    onClick={() => {
                        setStrokes([]);
                        pushToHistory(layers, []);
                    }}
                    className="p-1.5 text-white/70 hover:text-red-400 transition-colors"
                    title="Clear Drawing"
                 >
                     <Trash2 size={16} />
                 </button>
            </div>
        )}
      </Editor>

      {selectedId && selectedLayer && (
        <FloatingToolbar
          layer={selectedLayer}
          containerRef={containerRef}
          onUpdate={updateLayer}
          onDelete={deleteLayer}
          onClose={() => setSelectedId(null)}
        />
      )}
    </div>
  );
}

import React, { useRef, useState } from 'react';
import { TextLayer } from '../types';
import { Trash2, Scaling } from 'lucide-react';

interface TextOverlayProps {
  layer: TextLayer;
  isSelected: boolean;
  containerSize: { width: number; height: number };
  onSelect: (id: string) => void;
  onUpdate: (id: string, updates: Partial<TextLayer>, skipHistory?: boolean) => void;
  onDelete: (id: string) => void;
}

export const TextOverlay: React.FC<TextOverlayProps> = ({
  layer,
  isSelected,
  containerSize,
  onSelect,
  onUpdate,
  onDelete,
}) => {
  const [isDragging, setIsDragging] = useState(false);
  const [isResizingFont, setIsResizingFont] = useState(false);
  const [isResizingWidth, setIsResizingWidth] = useState(false);
  const [hasMoved, setHasMoved] = useState(false);

  const dragStart = useRef({ x: 0, y: 0 });
  const initialPos = useRef({ x: 0, y: 0 });
  const initialFontSize = useRef(1);
  const initialWidth = useRef(0);
  const initialDist = useRef(0);

  // --- Move Logic ---
  const handlePointerDown = (e: React.PointerEvent) => {
    e.stopPropagation();
    e.preventDefault(); 

    onSelect(layer.id);

    setIsDragging(true);
    setHasMoved(false); 
    dragStart.current = { x: e.clientX, y: e.clientY };
    initialPos.current = { x: layer.x, y: layer.y };

    (e.target as Element).setPointerCapture(e.pointerId);
  };

  const handlePointerMove = (e: React.PointerEvent) => {
    if (!isDragging || isResizingFont || isResizingWidth) return;
    e.preventDefault();

    const dx = e.clientX - dragStart.current.x;
    const dy = e.clientY - dragStart.current.y;

    if (!hasMoved && Math.hypot(dx, dy) < 5) return; 
    if (!hasMoved) setHasMoved(true);

    const dPctX = dx / containerSize.width;
    const dPctY = dy / containerSize.height;

    // Use skipHistory = true while dragging to prevent flooding history
    onUpdate(layer.id, {
      x: initialPos.current.x + dPctX,
      y: initialPos.current.y + dPctY,
    }, true);
  };

  const handlePointerUp = (e: React.PointerEvent) => {
    if (isDragging) {
      setIsDragging(false);
      if (hasMoved) {
        // Finally commit to history when interaction ends
        onUpdate(layer.id, {}); 
      }
      setHasMoved(false);
      (e.target as Element).releasePointerCapture(e.pointerId);
    }
  };

  // --- Font Resize Logic (Corner) ---
  const handleFontResizeStart = (e: React.PointerEvent) => {
    e.stopPropagation();
    e.preventDefault(); 
    setIsResizingFont(true);

    const rect = (e.currentTarget.closest('.group') as HTMLElement)?.getBoundingClientRect();
    if(rect) {
        const cx = rect.left + rect.width / 2;
        const cy = rect.top + rect.height / 2;
        initialDist.current = Math.hypot(e.clientX - cx, e.clientY - cy);
        initialFontSize.current = layer.fontSize;
    }

    (e.target as Element).setPointerCapture(e.pointerId);
  };

  const handleFontResizeMove = (e: React.PointerEvent) => {
    if (!isResizingFont) return;
    e.stopPropagation();
    e.preventDefault();

    const rect = (e.currentTarget.parentElement as HTMLElement)?.getBoundingClientRect();
    if(rect) {
        const cx = rect.left + rect.width / 2;
        const cy = rect.top + rect.height / 2;
        const currentDist = Math.hypot(e.clientX - cx, e.clientY - cy);

        const scale = currentDist / initialDist.current;
        let newFontSize = initialFontSize.current * scale;

        if (newFontSize < 0.2) newFontSize = 0.2;
        if (newFontSize > 10) newFontSize = 10;

        onUpdate(layer.id, { fontSize: newFontSize }, true);
    }
  };

  const handleFontResizeEnd = (e: React.PointerEvent) => {
    if (isResizingFont) {
        setIsResizingFont(false);
        // Commit to history
        onUpdate(layer.id, {}); 
        (e.target as Element).releasePointerCapture(e.pointerId);
    }
  };

  // --- Box Width Resize Logic (Side) ---
  const handleWidthResizeStart = (e: React.PointerEvent) => {
    e.stopPropagation();
    e.preventDefault();
    setIsResizingWidth(true);

    dragStart.current = { x: e.clientX, y: e.clientY };
    initialWidth.current = layer.maxWidth || 0; 

    (e.target as Element).setPointerCapture(e.pointerId);
  };

  const handleWidthResizeMove = (e: React.PointerEvent) => {
    if (!isResizingWidth) return;
    e.stopPropagation();

    const rect = (e.currentTarget.closest('.group') as HTMLElement)?.getBoundingClientRect();
    if (rect) {
        const cx = rect.left + rect.width / 2;
        const distFromCenter = Math.abs(e.clientX - cx);
        const newWidthPx = distFromCenter * 2;

        let newWidthPct = newWidthPx / containerSize.width;
        if (newWidthPct < 0.1) newWidthPct = 0.1; 
        if (newWidthPct > 1.0) newWidthPct = 1.0; 

        onUpdate(layer.id, { maxWidth: newWidthPct }, true);
    }
  };

  const handleWidthResizeEnd = (e: React.PointerEvent) => {
    if (isResizingWidth) {
        setIsResizingWidth(false);
        // Commit to history
        onUpdate(layer.id, {}); 
        (e.target as Element).releasePointerCapture(e.pointerId);
    }
  };

  const pixelFontSize = (containerSize.width / 20) * layer.fontSize;

  const getFontClass = (font: string) => {
    switch(font) {
        case 'font-anton': return 'font-[Anton]';
        case 'font-bebas': return 'font-["Bebas_Neue"]';
        case 'font-lobster': return 'font-[Lobster]';
        case 'font-oswald': return 'font-[Oswald]';
        case 'font-poppins': return 'font-[Poppins]';
        default: return font;
    }
  };

  return (
    <div
      className={`absolute select-none group touch-none flex items-center justify-center`}
      style={{
        left: `${layer.x * 100}%`,
        top: `${layer.y * 100}%`,
        width: layer.maxWidth ? `${layer.maxWidth * 100}%` : 'auto',
        transform: `translate(-50%, -50%) rotate(${layer.rotation}deg)`,
        zIndex: isSelected ? 50 : 10,
        cursor: isDragging ? 'grabbing' : 'grab',
      }}
      onPointerDown={handlePointerDown}
      onPointerMove={handlePointerMove}
      onPointerUp={handlePointerUp}
      onClick={(e) => e.stopPropagation()} 
    >
      {isSelected && (
        <div className="absolute inset-[-8px] border-2 border-white/50 border-dashed rounded-lg pointer-events-none">
           <button
            className="absolute -top-5 -right-5 bg-red-500 text-white p-2 rounded-full shadow-md hover:bg-red-600 pointer-events-auto transform hover:scale-110 transition-transform active:scale-95"
            onPointerDown={(e) => e.stopPropagation()} 
            onClick={(e) => {
              e.stopPropagation();
              onDelete(layer.id);
            }}
          >
            <Trash2 size={14} />
          </button>
        </div>
      )}

      {isSelected && (
          <div 
            className="absolute -bottom-6 -right-6 w-10 h-10 pointer-events-auto cursor-nwse-resize flex items-center justify-center z-50 group-hover:scale-110 transition-transform touch-none"
            onPointerDown={handleFontResizeStart}
            onPointerMove={handleFontResizeMove}
            onPointerUp={handleFontResizeEnd}
            onClick={(e) => e.stopPropagation()}
          >
            <div className="w-6 h-6 bg-blue-500 rounded-full shadow-lg border-2 border-white flex items-center justify-center">
               <Scaling size={12} className="text-white" />
            </div>
          </div>
      )}

      {isSelected && (
        <div 
          className="absolute right-[-14px] top-1/2 -translate-y-1/2 w-6 h-12 pointer-events-auto cursor-ew-resize flex items-center justify-center z-50 group-hover:scale-110 transition-transform touch-none"
          onPointerDown={handleWidthResizeStart}
          onPointerMove={handleWidthResizeMove}
          onPointerUp={handleWidthResizeEnd}
          onClick={(e) => e.stopPropagation()}
        >
           <div className="w-1.5 h-8 bg-white rounded-full shadow-lg border border-slate-400"></div>
        </div>
      )}

      {isSelected && (
        <div 
          className="absolute left-[-14px] top-1/2 -translate-y-1/2 w-6 h-12 pointer-events-auto cursor-ew-resize flex items-center justify-center z-50 group-hover:scale-110 transition-transform touch-none"
          onPointerDown={handleWidthResizeStart}
          onPointerMove={handleWidthResizeMove}
          onPointerUp={handleWidthResizeEnd}
          onClick={(e) => e.stopPropagation()}
        >
           <div className="w-1.5 h-8 bg-white rounded-full shadow-lg border border-slate-400"></div>
        </div>
      )}

      <div
        className={`whitespace-pre-wrap text-center leading-tight ${getFontClass(layer.fontFamily)}`}
        style={{
          color: layer.color,
          fontSize: `${pixelFontSize}px`,
          backgroundColor: layer.backgroundColor === 'transparent' ? 'transparent' : layer.backgroundColor,
          padding: layer.backgroundColor !== 'transparent' ? '0.2em 0.4em' : '0',
          borderRadius: '0.2em',
          textShadow: layer.backgroundColor === 'transparent' ? '0px 2px 4px rgba(0,0,0,0.5)' : 'none',
          minWidth: '20px',
          width: '100%',
        }}
      >
        {layer.content}
      </div>
    </div>
  );
};

import React, { useState, useRef, useEffect, useCallback } from 'react';
import { Upload, Plus, Download, Wand2, Type, Trash2, RefreshCw, Pen, Palette, Circle, Highlighter, Undo2, Redo2, GripHorizontal } from 'lucide-react';
import { Editor } from './components/Editor';
import { TextLayer, Stroke, FONT_FAMILY_MAP, COLORS } from './types';
import { generateSmartCaption } from './services/gemini';
import { FloatingToolbar } from './components/FloatingToolbar';

interface HistoryState {
  layers: TextLayer[];
  strokes: Stroke[];
}

export default function App() {
  const [images, setImages] = useState<string[]>([]);
  const [layers, setLayers] = useState<TextLayer[]>([]);
  const [strokes, setStrokes] = useState<Stroke[]>([]);
  const [selectedId, setSelectedId] = useState<string | null>(null);
  const [isProcessingAI, setIsProcessingAI] = useState(false);

  // History State
  const [history, setHistory] = useState<HistoryState[]>([]);
  const [historyIndex, setHistoryIndex] = useState(-1);

  // Drawing State
  const [isDrawing, setIsDrawing] = useState(false);
  const [drawingTool, setDrawingTool] = useState<'pen' | 'highlighter'>('pen');
  const [drawingColor, setDrawingColor] = useState('#EF4444');
  const [drawingSize, setDrawingSize] = useState(5);

  // Movable Drawing Toolbar State
  const [toolbarPos, setToolbarPos] = useState<{ x: number | null, y: number | null }>({ x: null, y: null });
  const [isDraggingToolbar, setIsDraggingToolbar] = useState(false);
  const dragOffset = useRef({ x: 0, y: 0 });

  const containerRef = useRef<HTMLDivElement>(null);

  // --- History Management ---

  const pushToHistory = useCallback((newLayers: TextLayer[], newStrokes: Stroke[]) => {
    setHistory(prev => {
      const newHistory = prev.slice(0, historyIndex + 1);
      const nextState = { layers: JSON.parse(JSON.stringify(newLayers)), strokes: JSON.parse(JSON.stringify(newStrokes)) };

      // Don't push identical state
      if (newHistory.length > 0) {
        const last = newHistory[newHistory.length - 1];
        if (JSON.stringify(last) === JSON.stringify(nextState)) return prev;
      }

      const updated = [...newHistory, nextState];
      // Limit history to 50 steps
      if (updated.length > 50) updated.shift();
      return updated;
    });
    setHistoryIndex(prev => {
      const newIdx = prev + 1;
      return Math.min(newIdx, 49); // Adjust based on shift
    });
  }, [historyIndex]);

  const undo = () => {
    if (historyIndex > 0) {
      const prevIdx = historyIndex - 1;
      const state = history[prevIdx];
      setLayers(state.layers);
      setStrokes(state.strokes);
      setHistoryIndex(prevIdx);
      setSelectedId(null);
    }
  };

  const redo = () => {
    if (historyIndex < history.length - 1) {
      const nextIdx = historyIndex + 1;
      const state = history[nextIdx];
      setLayers(state.layers);
      setStrokes(state.strokes);
      setHistoryIndex(nextIdx);
      setSelectedId(null);
    }
  };

  // Initialize history on first load/reset
  useEffect(() => {
    if (images.length > 0 && history.length === 0) {
      setHistory([{ layers: [], strokes: [] }]);
      setHistoryIndex(0);
    }
  }, [images, history.length]);

  // --- Drawing Toolbar Dragging ---
  const handleToolbarDragStart = (e: React.PointerEvent) => {
    e.stopPropagation();
    const rect = e.currentTarget.getBoundingClientRect();
    dragOffset.current = {
      x: e.clientX - rect.left,
      y: e.clientY - rect.top
    };
    setIsDraggingToolbar(true);
    (e.target as Element).setPointerCapture(e.pointerId);
  };

  const handleToolbarDragMove = (e: React.PointerEvent) => {
    if (!isDraggingToolbar || !containerRef.current) return;
    e.stopPropagation();

    const containerRect = containerRef.current.getBoundingClientRect();

    // Calculate new position relative to container
    let newX = e.clientX - containerRect.left - dragOffset.current.x;
    let newY = e.clientY - containerRect.top - dragOffset.current.y;

    // Clamp to container bounds
    const toolbarWidth = e.currentTarget.clientWidth;
    const toolbarHeight = e.currentTarget.clientHeight;

    newX = Math.max(0, Math.min(newX, containerRect.width - toolbarWidth));
    newY = Math.max(0, Math.min(newY, containerRect.height - toolbarHeight));

    setToolbarPos({ x: newX, y: newY });
  };

  const handleToolbarDragEnd = (e: React.PointerEvent) => {
    setIsDraggingToolbar(false);
    (e.target as Element).releasePointerCapture(e.pointerId);
  };

  // --- Actions ---

  const handleImageUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onload = (event) => {
        const result = event.target?.result as string;
        setImages(prev => {
          if (prev.length === 0) return [result];
          if (prev.length === 1) return [...prev, result];
          return [prev[0], result];
        });

        if (images.length === 0) {
            setLayers([]);
            setStrokes([]);
            setHistory([{ layers: [], strokes: [] }]);
            setHistoryIndex(0);
            setToolbarPos({ x: null, y: null });
        }
      };
      reader.readAsDataURL(file);
    }
  };

  const handleReset = () => {
    setImages([]);
    setLayers([]);
    setStrokes([]);
    setSelectedId(null);
    setIsDrawing(false);
    setHistory([]);
    setHistoryIndex(-1);
    setToolbarPos({ x: null, y: null });
  };

  const addTextLayer = (initialText = "Tap to edit") => {
    if (isDrawing) setIsDrawing(false);

    const newLayer: TextLayer = {
      id: crypto.randomUUID(),
      content: initialText,
      x: 0.5,
      y: 0.5,
      color: '#FFFFFF',
      backgroundColor: 'transparent',
      fontSize: 1.0,
      fontFamily: 'font-anton',
      rotation: 0,
    };
    const nextLayers = [...layers, newLayer];
    setLayers(nextLayers);
    setSelectedId(newLayer.id);
    pushToHistory(nextLayers, strokes);
  };

  const updateLayer = (id: string, updates: Partial<TextLayer>, skipHistory = false) => {
    const nextLayers = layers.map((layer) => (layer.id === id ? { ...layer, ...updates } : layer));
    setLayers(nextLayers);
    if (!skipHistory) {
      pushToHistory(nextLayers, strokes);
    }
  };

  const deleteLayer = (id: string) => {
    const nextLayers = layers.filter((l) => l.id !== id);
    setLayers(nextLayers);
    if (selectedId === id) setSelectedId(null);
    pushToHistory(nextLayers, strokes);
  };

  const handleAddStroke = (stroke: Stroke) => {
    const nextStrokes = [...strokes, stroke];
    setStrokes(nextStrokes);
    pushToHistory(layers, nextStrokes);
  };

  const handleSmartCaption = async () => {
    if (images.length === 0) return;
    setIsProcessingAI(true);
    try {
      const caption = await generateSmartCaption(images[0]);
      addTextLayer(caption);
    } catch (err) {
      alert("Failed to generate caption. Please check your API key or connection.");
    } finally {
      setIsProcessingAI(false);
    }
  };

  const loadImage = (src: string): Promise<HTMLImageElement> => {
    return new Promise((resolve, reject) => {
      const img = new Image();
      img.crossOrigin = "anonymous";
      img.onload = () => resolve(img);
      img.onerror = reject;
      img.src = src;
    });
  };

  const roundRect = (ctx: CanvasRenderingContext2D, x: number, y: number, width: number, height: number, radius: number) => {
    ctx.beginPath();
    ctx.moveTo(x + radius, y);
    ctx.lineTo(x + width - radius, y);
    ctx.quadraticCurveTo(x + width, y, x + width, y + radius);
    ctx.lineTo(x + width, y + height - radius);
    ctx.quadraticCurveTo(x + width, y + height, x + width - radius, y + height);
    ctx.lineTo(x + radius, y + height);
    ctx.quadraticCurveTo(x, y + height, x, y + height - radius);
    ctx.lineTo(x, y + radius);
    ctx.quadraticCurveTo(x, y, x + radius, y);
    ctx.closePath();
    ctx.fill();
  };

  const handleExport = async () => {
    if (images.length === 0) return;

    try {
        const canvas = document.createElement('canvas');
        const ctx = canvas.getContext('2d');
        if (!ctx) return;

        const loadedImages = await Promise.all(images.map(src => loadImage(src)));
        const img1 = loadedImages[0];

        let canvasWidth = img1.naturalWidth;
        const canvasHeight = img1.naturalHeight;

        let img2Specs: { img: HTMLImageElement, width: number, height: number, x: number } | null = null;

        if (loadedImages.length > 1) {
            const img2 = loadedImages[1];
            const scaleFactor = img1.naturalHeight / img2.naturalHeight;
            const scaledWidth = img2.naturalWidth * scaleFactor;

            img2Specs = {
                img: img2,
                width: scaledWidth,
                height: img1.naturalHeight,
                x: img1.naturalWidth
            };

            canvasWidth += scaledWidth;
        }

        canvas.width = canvasWidth;
        canvas.height = canvasHeight;

        ctx.drawImage(img1, 0, 0);
        if (img2Specs) {
            ctx.drawImage(img2Specs.img, img2Specs.x, 0, img2Specs.width, img2Specs.height);
        }

        ctx.lineCap = 'round';
        ctx.lineJoin = 'round';

        strokes.forEach(stroke => {
            if (stroke.points.length === 0) return;

            ctx.save();
            ctx.beginPath();
            ctx.strokeStyle = stroke.color;
            ctx.globalAlpha = stroke.opacity;
            const strokeScale = canvasWidth / (containerRef.current?.clientWidth || canvasWidth);
            ctx.lineWidth = stroke.size * strokeScale;

            const points = stroke.points;

            if (points.length < 3) {
                ctx.moveTo(points[0].x * canvasWidth, points[0].y * canvasHeight);
                for(let i=1; i<points.length; i++) {
                    ctx.lineTo(points[i].x * canvasWidth, points[i].y * canvasHeight);
                }
            } else {
                ctx.moveTo(points[0].x * canvasWidth, points[0].y * canvasHeight);
                let i;
                for (i = 1; i < points.length - 2; i++) {
                    const xc = (points[i].x + points[i + 1].x) / 2;
                    const yc = (points[i].y + points[i + 1].y) / 2;
                    ctx.quadraticCurveTo(
                        points[i].x * canvasWidth, 
                        points[i].y * canvasHeight, 
                        xc * canvasWidth, 
                        yc * canvasHeight
                    );
                }
                ctx.quadraticCurveTo(
                    points[i].x * canvasWidth, 
                    points[i].y * canvasHeight, 
                    points[i+1].x * canvasWidth, 
                    points[i+1].y * canvasHeight
                );
            }

            ctx.stroke();
            ctx.restore();
        });

        layers.forEach((layer) => {
            const fontSizePx = (canvasWidth / 20) * layer.fontSize;

            ctx.save();
            const x = layer.x * canvasWidth;
            const y = layer.y * canvasHeight;

            ctx.translate(x, y);
            ctx.rotate((layer.rotation * Math.PI) / 180);

            let fontFamily = FONT_FAMILY_MAP[layer.fontFamily] || 'sans-serif';
            fontFamily = fontFamily.replace(/"/g, ''); 

            ctx.font = `bold ${fontSizePx}px ${fontFamily}`;
            ctx.textAlign = 'center';
            ctx.textBaseline = 'middle';

            let lines = layer.content.split('\n');
            if (layer.maxWidth) {
                const maxPx = layer.maxWidth * canvasWidth;
                const wrappedLines: string[] = [];
                lines.forEach(paragraph => {
                    const words = paragraph.split(' ');
                    let currentLine = words[0];
                    for (let i = 1; i < words.length; i++) {
                        const word = words[i];
                        const width = ctx.measureText(currentLine + " " + word).width;
                        if (width < maxPx) {
                            currentLine += " " + word;
                        } else {
                            wrappedLines.push(currentLine);
                            currentLine = word;
                        }
                    }
                    wrappedLines.push(currentLine);
                });
                lines = wrappedLines;
            }

            const lineHeight = fontSizePx * 1.2;
            const totalHeight = lines.length * lineHeight;

            let maxLineWidth = 0;
            lines.forEach(line => {
                const metrics = ctx.measureText(line);
                if (metrics.width > maxLineWidth) maxLineWidth = metrics.width;
            });

            if (layer.backgroundColor !== 'transparent') {
                const paddingX = fontSizePx * 0.4;
                const paddingY = fontSizePx * 0.2;
                const bgWidth = maxLineWidth + (paddingX * 2);
                const bgHeight = totalHeight + (paddingY * 2);

                ctx.fillStyle = layer.backgroundColor;
                roundRect(
                    ctx, 
                    -bgWidth / 2, 
                    -bgHeight / 2, 
                    bgWidth, 
                    bgHeight, 
                    fontSizePx * 0.2
                );
            } else {
                ctx.shadowColor = 'rgba(0, 0, 0, 0.5)';
                ctx.shadowBlur = 4;
                ctx.shadowOffsetY = 2;
            }

            ctx.fillStyle = layer.color;
            if (layer.backgroundColor !== 'transparent') {
                 ctx.shadowColor = 'transparent';
            }

            let startY = -(totalHeight / 2) + (lineHeight / 2);
            lines.forEach((line, i) => {
                ctx.fillText(line, 0, startY + (i * lineHeight));
            });

            ctx.restore();
        });

        const link = document.createElement('a');
        link.download = `snaptext-${Date.now()}.png`;
        link.href = canvas.toDataURL('image/png');
        link.click();

    } catch (e) {
        console.error("Export failed", e);
        alert("Failed to export image.");
    }
  };

  const currentOpacity = drawingTool === 'highlighter' ? 0.45 : 1.0;
  const displayDrawingSize = drawingTool === 'highlighter' ? drawingSize * 3 : drawingSize;

  if (images.length === 0) {
    return (
      <div className="h-screen w-full flex flex-col items-center justify-center bg-slate-900 text-white p-6 relative overflow-hidden">
        <div className="absolute top-[-10%] left-[-10%] w-[40%] h-[40%] bg-purple-600 rounded-full blur-[120px] opacity-20"></div>
        <div className="absolute bottom-[-10%] right-[-10%] w-[40%] h-[40%] bg-blue-600 rounded-full blur-[120px] opacity-20"></div>

        <div className="z-10 text-center max-w-md">
          <div className="mb-6 flex justify-center">
            <div className="w-20 h-20 bg-gradient-to-tr from-purple-500 to-pink-500 rounded-2xl flex items-center justify-center shadow-lg transform rotate-3">
               <Type size={40} className="text-white" />
            </div>
          </div>
          <h1 className="text-4xl font-extrabold mb-4 tracking-tight">SnapText Editor</h1>
          <p className="text-slate-400 mb-8 text-lg">
            Add bold, beautiful text to your photos. Messenger-style editing with side-by-side support.
          </p>

          <label className="group relative inline-flex items-center justify-center px-8 py-4 text-lg font-bold text-white transition-all duration-200 bg-blue-600 font-pj rounded-full focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-blue-600 hover:bg-blue-500 cursor-pointer shadow-lg shadow-blue-500/30">
            <span className="absolute inset-0 transition-transform translate-x-1 translate-y-1 bg-blue-700 group-hover:translate-y-0 group-hover:translate-x-0 rounded-full"></span>
            <span className="relative flex items-center gap-2">
              <Upload size={24} />
              <span>Choose Photo</span>
            </span>
            <input type="file" accept="image/*" onChange={handleImageUpload} className="hidden" />
          </label>
        </div>
      </div>
    );
  }

  const selectedLayer = layers.find(l => l.id === selectedId);

  return (
    <div className="h-screen w-full flex flex-col bg-slate-950 text-white overflow-hidden relative">
      <header className="h-16 px-4 flex items-center justify-between border-b border-slate-800 bg-slate-900/50 backdrop-blur-md z-40">
        <div className="flex items-center gap-2 font-bold text-xl tracking-tight">
          <span className="text-blue-500">Snap</span>Text
        </div>

        <div className="flex items-center gap-2">
          <button 
            onClick={undo}
            disabled={historyIndex <= 0}
            className="p-2 text-slate-300 hover:text-white disabled:opacity-30 disabled:cursor-not-allowed transition-all"
            title="Undo"
          >
            <Undo2 size={20} />
          </button>
          <button 
            onClick={redo}
            disabled={historyIndex >= history.length - 1}
            className="p-2 text-slate-300 hover:text-white disabled:opacity-30 disabled:cursor-not-allowed transition-all"
            title="Redo"
          >
            <Redo2 size={20} />
          </button>
        </div>

        <div className="flex gap-3">
          {images.length < 2 && (
            <label className="flex items-center gap-2 px-3 py-2 bg-slate-800 hover:bg-slate-700 text-slate-200 rounded-full text-sm font-medium transition-colors cursor-pointer border border-slate-700">
               <Plus size={16} />
               <span>Add Photo</span>
               <input type="file" accept="image/*" onChange={handleImageUpload} className="hidden" />
            </label>
          )}
          <button 
            onClick={handleExport}
            className="flex items-center gap-2 px-4 py-2 bg-blue-600 hover:bg-blue-500 text-white rounded-full text-sm font-semibold transition-all shadow-md shadow-blue-500/20"
          >
            <Download size={16} />
            Save
          </button>
        </div>
      </header>

      <Editor
        images={images}
        layers={layers}
        selectedId={selectedId}
        strokes={strokes}
        isDrawing={isDrawing}
        drawingColor={drawingColor}
        drawingSize={displayDrawingSize}
        drawingOpacity={currentOpacity}
        onSelectLayer={setSelectedId}
        onUpdateLayer={updateLayer}
        onDeleteLayer={deleteLayer}
        onAddStroke={handleAddStroke}
        containerRef={containerRef}
      >
        {!selectedId && (
            <div className="absolute top-4 right-4 z-[60] flex flex-col gap-4">
                <button 
                  onClick={() => addTextLayer()}
                  className={`flex flex-col items-center gap-1 group ${isDrawing ? 'opacity-50' : ''}`}
                  title="Add Text"
                >
                    <div className="w-10 h-10 bg-slate-900/60 backdrop-blur-md border border-white/10 rounded-full flex items-center justify-center shadow-lg hover:bg-slate-800 text-white transition-all transform group-hover:scale-105">
                        <Type size={20} />
                    </div>
                    <span className="text-[10px] font-semibold text-white/90 drop-shadow-md">Text</span>
                </button>

                <button 
                  onClick={() => {
                    setIsDrawing(!isDrawing);
                    setSelectedId(null);
                  }}
                  className={`flex flex-col items-center gap-1 group`}
                  title="Draw"
                >
                    <div className={`w-10 h-10 backdrop-blur-md border border-white/10 rounded-full flex items-center justify-center shadow-lg text-white transition-all transform group-hover:scale-105 ${isDrawing ? 'bg-blue-600 border-blue-400' : 'bg-slate-900/60 hover:bg-slate-800'}`}>
                        {drawingTool === 'pen' ? <Pen size={18} /> : <Highlighter size={18} />}
                    </div>
                    <span className="text-[10px] font-semibold text-white/90 drop-shadow-md">Draw</span>
                </button>

                <button 
                  onClick={handleSmartCaption}
                  disabled={isProcessingAI}
                  className={`flex flex-col items-center gap-1 group disabled:opacity-50 ${isDrawing ? 'opacity-50' : ''}`}
                  title="Magic Caption"
                >
                    <div className="w-10 h-10 bg-gradient-to-tr from-purple-600/80 to-blue-600/80 backdrop-blur-md border border-white/10 rounded-full flex items-center justify-center shadow-lg hover:brightness-110 text-white transition-all transform group-hover:scale-105">
                        {isProcessingAI ? <div className="w-4 h-4 border-2 border-white/50 border-t-white rounded-full animate-spin" /> : <Wand2 size={20} />}
                    </div>
                    <span className="text-[10px] font-semibold text-white/90 drop-shadow-md">Magic</span>
                </button>

                <button 
                  onClick={handleReset}
                  className="flex flex-col items-center gap-1 group"
                  title="Reset All"
                >
                    <div className="w-10 h-10 bg-slate-900/60 backdrop-blur-md border border-white/10 rounded-full flex items-center justify-center shadow-lg hover:bg-red-500/80 text-white transition-all transform group-hover:scale-105">
                        <RefreshCw size={18} />
                    </div>
                    <span className="text-[10px] font-semibold text-white/90 drop-shadow-md">Reset</span>
                </button>
            </div>
        )}

        {isDrawing && !selectedId && (
            <div 
                className="absolute flex items-center gap-2 p-2 bg-slate-900/90 backdrop-blur-md rounded-full border border-white/10 z-[60] shadow-2xl touch-none select-none animate-in slide-in-from-bottom-5"
                style={{
                    left: toolbarPos.x !== null ? `${toolbarPos.x}px` : '50%',
                    top: toolbarPos.y !== null ? `${toolbarPos.y}px` : 'auto',
                    bottom: toolbarPos.y === null ? '24px' : 'auto',
                    transform: toolbarPos.x === null ? 'translateX(-50%)' : 'none',
                }}
                onPointerMove={handleToolbarDragMove}
                onPointerUp={handleToolbarDragEnd}
            >
                 <div 
                    className="cursor-move p-2 text-white/40 hover:text-white transition-colors"
                    onPointerDown={handleToolbarDragStart}
                 >
                    <GripHorizontal size={18} />
                 </div>

                 <div className="w-[1px] h-6 bg-white/10 mx-1"></div>

                 <div className="flex gap-1 px-1">
                    <button 
                        onClick={() => setDrawingTool('pen')}
                        className={`p-2 rounded-full transition-all ${drawingTool === 'pen' ? 'bg-white text-black' : 'text-white hover:bg-white/10'}`}
                        title="Pen"
                    >
                        <Pen size={16} />
                    </button>
                    <button 
                        onClick={() => setDrawingTool('highlighter')}
                        className={`p-2 rounded-full transition-all ${drawingTool === 'highlighter' ? 'bg-white text-black' : 'text-white hover:bg-white/10'}`}
                        title="Highlighter"
                    >
                        <Highlighter size={16} />
                    </button>
                 </div>

                 <div className="w-[1px] h-6 bg-white/20 mx-1"></div>

                 <div className="flex gap-2 px-2">
                    {COLORS.map(color => (
                        <button
                            key={color}
                            className={`w-6 h-6 rounded-full border-2 transition-transform ${drawingColor === color ? 'border-white scale-110' : 'border-transparent hover:scale-105'}`}
                            style={{ backgroundColor: color }}
                            onClick={() => setDrawingColor(color)}
                        />
                    ))}
                 </div>

                 <div className="w-[1px] h-6 bg-white/20 mx-1"></div>

                 <div className="flex gap-2 px-2 items-center">
                    <button onClick={() => setDrawingSize(Math.max(2, drawingSize - 2))} className="p-1 hover:text-blue-400"><Circle size={8} fill="currentColor" /></button>
                    <span className="text-xs w-4 text-center tabular-nums">{drawingSize}</span>
                    <button onClick={() => setDrawingSize(Math.min(20, drawingSize + 2))} className="p-1 hover:text-blue-400"><Circle size={16} fill="currentColor" /></button>
                 </div>

                 <div className="w-[1px] h-6 bg-white/20 mx-1"></div>

                 <button 
                    onClick={() => {
                        setStrokes([]);
                        pushToHistory(layers, []);
                    }}
                    className="p-1.5 text-white/70 hover:text-red-400 transition-colors"
                    title="Clear Drawing"
                 >
                     <Trash2 size={16} />
                 </button>
            </div>
        )}
      </Editor>

      {selectedId && selectedLayer && (
        <FloatingToolbar
          layer={selectedLayer}
          containerRef={containerRef}
          onUpdate={updateLayer}
          onDelete={deleteLayer}
          onClose={() => setSelectedId(null)}
        />
      )}
    </div>
  );
}

import React, { useState, useRef, useEffect, useCallback } from 'react';
import { Upload, Plus, Download, Wand2, Type, Trash2, RefreshCw, Pen, Palette, Circle, Highlighter, Undo2, Redo2, GripHorizontal } from 'lucide-react';
import { Editor } from './components/Editor';
import { TextLayer, Stroke, FONT_FAMILY_MAP, COLORS } from './types';
import { generateSmartCaption } from './services/gemini';
import { FloatingToolbar } from './components/FloatingToolbar';

interface HistoryState {
  layers: TextLayer[];
  strokes: Stroke[];
}

export default function App() {
  const [images, setImages] = useState<string[]>([]);
  const [layers, setLayers] = useState<TextLayer[]>([]);
  const [strokes, setStrokes] = useState<Stroke[]>([]);
  const [selectedId, setSelectedId] = useState<string | null>(null);
  const [isProcessingAI, setIsProcessingAI] = useState(false);

  // History State
  const [history, setHistory] = useState<HistoryState[]>([]);
  const [historyIndex, setHistoryIndex] = useState(-1);

  // Drawing State
  const [isDrawing, setIsDrawing] = useState(false);
  const [drawingTool, setDrawingTool] = useState<'pen' | 'highlighter'>('pen');
  const [drawingColor, setDrawingColor] = useState('#EF4444');
  const [drawingSize, setDrawingSize] = useState(5);

  // Movable Drawing Toolbar State
  const [toolbarPos, setToolbarPos] = useState<{ x: number | null, y: number | null }>({ x: null, y: null });
  const [isDraggingToolbar, setIsDraggingToolbar] = useState(false);
  const toolbarRef = useRef<HTMLDivElement>(null);
  const dragOffset = useRef({ x: 0, y: 0 });

  const containerRef = useRef<HTMLDivElement>(null);

  // --- History Management ---

  const pushToHistory = useCallback((newLayers: TextLayer[], newStrokes: Stroke[]) => {
    setHistory(prev => {
      const newHistory = prev.slice(0, historyIndex + 1);
      const nextState = { layers: JSON.parse(JSON.stringify(newLayers)), strokes: JSON.parse(JSON.stringify(newStrokes)) };

      if (newHistory.length > 0) {
        const last = newHistory[newHistory.length - 1];
        if (JSON.stringify(last) === JSON.stringify(nextState)) return prev;
      }

      const updated = [...newHistory, nextState];
      if (updated.length > 50) updated.shift();
      return updated;
    });
    setHistoryIndex(prev => {
      const newIdx = prev + 1;
      return Math.min(newIdx, 49);
    });
  }, [historyIndex]);

  const undo = () => {
    if (historyIndex > 0) {
      const prevIdx = historyIndex - 1;
      const state = history[prevIdx];
      setLayers(state.layers);
      setStrokes(state.strokes);
      setHistoryIndex(prevIdx);
      setSelectedId(null);
    }
  };

  const redo = () => {
    if (historyIndex < history.length - 1) {
      const nextIdx = historyIndex + 1;
      const state = history[nextIdx];
      setLayers(state.layers);
      setStrokes(state.strokes);
      setHistoryIndex(nextIdx);
      setSelectedId(null);
    }
  };

  useEffect(() => {
    if (images.length > 0 && history.length === 0) {
      setHistory([{ layers: [], strokes: [] }]);
      setHistoryIndex(0);
    }
  }, [images, history.length]);

  // --- Drawing Toolbar Dragging Logic ---
  const handleToolbarDragStart = (e: React.PointerEvent) => {
    if (!toolbarRef.current) return;
    e.stopPropagation();
    const rect = toolbarRef.current.getBoundingClientRect();
    dragOffset.current = {
      x: e.clientX - rect.left,
      y: e.clientY - rect.top
    };
    setIsDraggingToolbar(true);
  };

  useEffect(() => {
    if (!isDraggingToolbar) return;

    const handlePointerMove = (e: PointerEvent) => {
      if (!containerRef.current || !toolbarRef.current) return;

      const containerRect = containerRef.current.getBoundingClientRect();
      const toolbarWidth = toolbarRef.current.clientWidth;
      const toolbarHeight = toolbarRef.current.clientHeight;

      let newX = e.clientX - containerRect.left - dragOffset.current.x;
      let newY = e.clientY - containerRect.top - dragOffset.current.y;

      // Keep within image boundaries
      newX = Math.max(0, Math.min(newX, containerRect.width - toolbarWidth));
      newY = Math.max(0, Math.min(newY, containerRect.height - toolbarHeight));

      setToolbarPos({ x: newX, y: newY });
    };

    const handlePointerUp = () => {
      setIsDraggingToolbar(false);
    };

    window.addEventListener('pointermove', handlePointerMove);
    window.addEventListener('pointerup', handlePointerUp);
    return () => {
      window.removeEventListener('pointermove', handlePointerMove);
      window.removeEventListener('pointerup', handlePointerUp);
    };
  }, [isDraggingToolbar]);

  // --- Actions ---

  const handleImageUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onload = (event) => {
        const result = event.target?.result as string;
        setImages(prev => {
          if (prev.length === 0) return [result];
          if (prev.length === 1) return [...prev, result];
          return [prev[0], result];
        });

        if (images.length === 0) {
            setLayers([]);
            setStrokes([]);
            setHistory([{ layers: [], strokes: [] }]);
            setHistoryIndex(0);
            setToolbarPos({ x: null, y: null });
        }
      };
      reader.readAsDataURL(file);
    }
  };

  const handleReset = () => {
    setImages([]);
    setLayers([]);
    setStrokes([]);
    setSelectedId(null);
    setIsDrawing(false);
    setHistory([]);
    setHistoryIndex(-1);
    setToolbarPos({ x: null, y: null });
  };

  const addTextLayer = (initialText = "Tap to edit") => {
    if (isDrawing) setIsDrawing(false);

    const newLayer: TextLayer = {
      id: crypto.randomUUID(),
      content: initialText,
      x: 0.5,
      y: 0.5,
      color: '#FFFFFF',
      backgroundColor: 'transparent',
      fontSize: 1.0,
      fontFamily: 'font-anton',
      rotation: 0,
    };
    const nextLayers = [...layers, newLayer];
    setLayers(nextLayers);
    setSelectedId(newLayer.id);
    pushToHistory(nextLayers, strokes);
  };

  const updateLayer = (id: string, updates: Partial<TextLayer>, skipHistory = false) => {
    const nextLayers = layers.map((layer) => (layer.id === id ? { ...layer, ...updates } : layer));
    setLayers(nextLayers);
    if (!skipHistory) {
      pushToHistory(nextLayers, strokes);
    }
  };

  const deleteLayer = (id: string) => {
    const nextLayers = layers.filter((l) => l.id !== id);
    setLayers(nextLayers);
    if (selectedId === id) setSelectedId(null);
    pushToHistory(nextLayers, strokes);
  };

  const handleAddStroke = (stroke: Stroke) => {
    const nextStrokes = [...strokes, stroke];
    setStrokes(nextStrokes);
    pushToHistory(layers, nextStrokes);
  };

  const handleSmartCaption = async () => {
    if (images.length === 0) return;
    setIsProcessingAI(true);
    try {
      const caption = await generateSmartCaption(images[0]);
      addTextLayer(caption);
    } catch (err) {
      alert("Failed to generate caption. Please check your API key or connection.");
    } finally {
      setIsProcessingAI(false);
    }
  };

  const loadImage = (src: string): Promise<HTMLImageElement> => {
    return new Promise((resolve, reject) => {
      const img = new Image();
      img.crossOrigin = "anonymous";
      img.onload = () => resolve(img);
      img.onerror = reject;
      img.src = src;
    });
  };

  const roundRect = (ctx: CanvasRenderingContext2D, x: number, y: number, width: number, height: number, radius: number) => {
    ctx.beginPath();
    ctx.moveTo(x + radius, y);
    ctx.lineTo(x + width - radius, y);
    ctx.quadraticCurveTo(x + width, y, x + width, y + radius);
    ctx.lineTo(x + width, y + height - radius);
    ctx.quadraticCurveTo(x + width, y + height, x + width - radius, y + height);
    ctx.lineTo(x + radius, y + height);
    ctx.quadraticCurveTo(x, y + height, x, y + height - radius);
    ctx.lineTo(x, y + radius);
    ctx.quadraticCurveTo(x, y, x + radius, y);
    ctx.closePath();
    ctx.fill();
  };

  const handleExport = async () => {
    if (images.length === 0) return;

    try {
        const canvas = document.createElement('canvas');
        const ctx = canvas.getContext('2d');
        if (!ctx) return;

        const loadedImages = await Promise.all(images.map(src => loadImage(src)));
        const img1 = loadedImages[0];

        let canvasWidth = img1.naturalWidth;
        const canvasHeight = img1.naturalHeight;

        let img2Specs: { img: HTMLImageElement, width: number, height: number, x: number } | null = null;

        if (loadedImages.length > 1) {
            const img2 = loadedImages[1];
            const scaleFactor = img1.naturalHeight / img2.naturalHeight;
            const scaledWidth = img2.naturalWidth * scaleFactor;

            img2Specs = {
                img: img2,
                width: scaledWidth,
                height: img1.naturalHeight,
                x: img1.naturalWidth
            };

            canvasWidth += scaledWidth;
        }

        canvas.width = canvasWidth;
        canvas.height = canvasHeight;

        ctx.drawImage(img1, 0, 0);
        if (img2Specs) {
            ctx.drawImage(img2Specs.img, img2Specs.x, 0, img2Specs.width, img2Specs.height);
        }

        ctx.lineCap = 'round';
        ctx.lineJoin = 'round';

        strokes.forEach(stroke => {
            if (stroke.points.length === 0) return;

            ctx.save();
            ctx.beginPath();
            ctx.strokeStyle = stroke.color;
            ctx.globalAlpha = stroke.opacity;
            const strokeScale = canvasWidth / (containerRef.current?.clientWidth || canvasWidth);
            ctx.lineWidth = stroke.size * strokeScale;

            const points = stroke.points;

            if (points.length < 3) {
                ctx.moveTo(points[0].x * canvasWidth, points[0].y * canvasHeight);
                for(let i=1; i<points.length; i++) {
                    ctx.lineTo(points[i].x * canvasWidth, points[i].y * canvasHeight);
                }
            } else {
                ctx.moveTo(points[0].x * canvasWidth, points[0].y * canvasHeight);
                let i;
                for (i = 1; i < points.length - 2; i++) {
                    const xc = (points[i].x + points[i + 1].x) / 2;
                    const yc = (points[i].y + points[i + 1].y) / 2;
                    ctx.quadraticCurveTo(
                        points[i].x * canvasWidth, 
                        points[i].y * canvasHeight, 
                        xc * canvasWidth, 
                        yc * canvasHeight
                    );
                }
                ctx.quadraticCurveTo(
                    points[i].x * canvasWidth, 
                    points[i].y * canvasHeight, 
                    points[i+1].x * canvasWidth, 
                    points[i+1].y * canvasHeight
                );
            }

            ctx.stroke();
            ctx.restore();
        });

        layers.forEach((layer) => {
            const fontSizePx = (canvasWidth / 20) * layer.fontSize;

            ctx.save();
            const x = layer.x * canvasWidth;
            const y = layer.y * canvasHeight;

            ctx.translate(x, y);
            ctx.rotate((layer.rotation * Math.PI) / 180);

            let fontFamily = FONT_FAMILY_MAP[layer.fontFamily] || 'sans-serif';
            fontFamily = fontFamily.replace(/"/g, ''); 

            ctx.font = `bold ${fontSizePx}px ${fontFamily}`;
            ctx.textAlign = 'center';
            ctx.textBaseline = 'middle';

            let lines = layer.content.split('\n');
            if (layer.maxWidth) {
                const maxPx = layer.maxWidth * canvasWidth;
                const wrappedLines: string[] = [];
                lines.forEach(paragraph => {
                    const words = paragraph.split(' ');
                    let currentLine = words[0];
                    for (let i = 1; i < words.length; i++) {
                        const word = words[i];
                        const width = ctx.measureText(currentLine + " " + word).width;
                        if (width < maxPx) {
                            currentLine += " " + word;
                        } else {
                            wrappedLines.push(currentLine);
                            currentLine = word;
                        }
                    }
                    wrappedLines.push(currentLine);
                });
                lines = wrappedLines;
            }

            const lineHeight = fontSizePx * 1.2;
            const totalHeight = lines.length * lineHeight;

            let maxLineWidth = 0;
            lines.forEach(line => {
                const metrics = ctx.measureText(line);
                if (metrics.width > maxLineWidth) maxLineWidth = metrics.width;
            });

            if (layer.backgroundColor !== 'transparent') {
                const paddingX = fontSizePx * 0.4;
                const paddingY = fontSizePx * 0.2;
                const bgWidth = maxLineWidth + (paddingX * 2);
                const bgHeight = totalHeight + (paddingY * 2);

                ctx.fillStyle = layer.backgroundColor;
                roundRect(
                    ctx, 
                    -bgWidth / 2, 
                    -bgHeight / 2, 
                    bgWidth, 
                    bgHeight, 
                    fontSizePx * 0.2
                );
            } else {
                ctx.shadowColor = 'rgba(0, 0, 0, 0.5)';
                ctx.shadowBlur = 4;
                ctx.shadowOffsetY = 2;
            }

            ctx.fillStyle = layer.color;
            if (layer.backgroundColor !== 'transparent') {
                 ctx.shadowColor = 'transparent';
            }

            let startY = -(totalHeight / 2) + (lineHeight / 2);
            lines.forEach((line, i) => {
                ctx.fillText(line, 0, startY + (i * lineHeight));
            });

            ctx.restore();
        });

        const link = document.createElement('a');
        link.download = `snaptext-${Date.now()}.png`;
        link.href = canvas.toDataURL('image/png');
        link.click();

    } catch (e) {
        console.error("Export failed", e);
        alert("Failed to export image.");
    }
  };

  const currentOpacity = drawingTool === 'highlighter' ? 0.45 : 1.0;
  const displayDrawingSize = drawingTool === 'highlighter' ? drawingSize * 3 : drawingSize;

  if (images.length === 0) {
    return (
      <div className="h-screen w-full flex flex-col items-center justify-center bg-slate-900 text-white p-6 relative overflow-hidden">
        <div className="absolute top-[-10%] left-[-10%] w-[40%] h-[40%] bg-purple-600 rounded-full blur-[120px] opacity-20"></div>
        <div className="absolute bottom-[-10%] right-[-10%] w-[40%] h-[40%] bg-blue-600 rounded-full blur-[120px] opacity-20"></div>

        <div className="z-10 text-center max-w-md">
          <div className="mb-6 flex justify-center">
            <div className="w-20 h-20 bg-gradient-to-tr from-purple-500 to-pink-500 rounded-2xl flex items-center justify-center shadow-lg transform rotate-3">
               <Type size={40} className="text-white" />
            </div>
          </div>
          <h1 className="text-4xl font-extrabold mb-4 tracking-tight">SnapText Editor</h1>
          <p className="text-slate-400 mb-8 text-lg">
            Add bold, beautiful text to your photos. Messenger-style editing with side-by-side support.
          </p>

          <label className="group relative inline-flex items-center justify-center px-8 py-4 text-lg font-bold text-white transition-all duration-200 bg-blue-600 font-pj rounded-full focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-blue-600 hover:bg-blue-500 cursor-pointer shadow-lg shadow-blue-500/30">
            <span className="absolute inset-0 transition-transform translate-x-1 translate-y-1 bg-blue-700 group-hover:translate-y-0 group-hover:translate-x-0 rounded-full"></span>
            <span className="relative flex items-center gap-2">
              <Upload size={24} />
              <span>Choose Photo</span>
            </span>
            <input type="file" accept="image/*" onChange={handleImageUpload} className="hidden" />
          </label>
        </div>
      </div>
    );
  }

  const selectedLayer = layers.find(l => l.id === selectedId);

  return (
    <div className="h-screen w-full flex flex-col bg-slate-950 text-white overflow-hidden relative">
      <header className="h-16 px-4 flex items-center justify-between border-b border-slate-800 bg-slate-900/50 backdrop-blur-md z-40">
        <div className="flex items-center gap-2 font-bold text-xl tracking-tight">
          <span className="text-blue-500">Snap</span>Text
        </div>

        <div className="flex items-center gap-2">
          <button 
            onClick={undo}
            disabled={historyIndex <= 0}
            className="p-2 text-slate-300 hover:text-white disabled:opacity-30 disabled:cursor-not-allowed transition-all"
            title="Undo"
          >
            <Undo2 size={20} />
          </button>
          <button 
            onClick={redo}
            disabled={historyIndex >= history.length - 1}
            className="p-2 text-slate-300 hover:text-white disabled:opacity-30 disabled:cursor-not-allowed transition-all"
            title="Redo"
          >
            <Redo2 size={20} />
          </button>
        </div>

        <div className="flex gap-3">
          {images.length < 2 && (
            <label className="flex items-center gap-2 px-3 py-2 bg-slate-800 hover:bg-slate-700 text-slate-200 rounded-full text-sm font-medium transition-colors cursor-pointer border border-slate-700">
               <Plus size={16} />
               <span>Add Photo</span>
               <input type="file" accept="image/*" onChange={handleImageUpload} className="hidden" />
            </label>
          )}
          <button 
            onClick={handleExport}
            className="flex items-center gap-2 px-4 py-2 bg-blue-600 hover:bg-blue-500 text-white rounded-full text-sm font-semibold transition-all shadow-md shadow-blue-500/20"
          >
            <Download size={16} />
            Save
          </button>
        </div>
      </header>

      <Editor
        images={images}
        layers={layers}
        selectedId={selectedId}
        strokes={strokes}
        isDrawing={isDrawing}
        drawingColor={drawingColor}
        drawingSize={displayDrawingSize}
        drawingOpacity={currentOpacity}
        onSelectLayer={setSelectedId}
        onUpdateLayer={updateLayer}
        onDeleteLayer={deleteLayer}
        onAddStroke={handleAddStroke}
        containerRef={containerRef}
      >
        {!selectedId && (
            <div className="absolute top-4 right-4 z-[60] flex flex-col gap-4">
                <button 
                  onClick={() => addTextLayer()}
                  className={`flex flex-col items-center gap-1 group ${isDrawing ? 'opacity-50' : ''}`}
                  title="Add Text"
                >
                    <div className="w-10 h-10 bg-slate-900/60 backdrop-blur-md border border-white/10 rounded-full flex items-center justify-center shadow-lg hover:bg-slate-800 text-white transition-all transform group-hover:scale-105">
                        <Type size={20} />
                    </div>
                    <span className="text-[10px] font-semibold text-white/90 drop-shadow-md">Text</span>
                </button>

                <button 
                  onClick={() => {
                    setIsDrawing(!isDrawing);
                    setSelectedId(null);
                  }}
                  className={`flex flex-col items-center gap-1 group`}
                  title="Draw"
                >
                    <div className={`w-10 h-10 backdrop-blur-md border border-white/10 rounded-full flex items-center justify-center shadow-lg text-white transition-all transform group-hover:scale-105 ${isDrawing ? 'bg-blue-600 border-blue-400' : 'bg-slate-900/60 hover:bg-slate-800'}`}>
                        {drawingTool === 'pen' ? <Pen size={18} /> : <Highlighter size={18} />}
                    </div>
                    <span className="text-[10px] font-semibold text-white/90 drop-shadow-md">Draw</span>
                </button>

                <button 
                  onClick={handleSmartCaption}
                  disabled={isProcessingAI}
                  className={`flex flex-col items-center gap-1 group disabled:opacity-50 ${isDrawing ? 'opacity-50' : ''}`}
                  title="Magic Caption"
                >
                    <div className="w-10 h-10 bg-gradient-to-tr from-purple-600/80 to-blue-600/80 backdrop-blur-md border border-white/10 rounded-full flex items-center justify-center shadow-lg hover:brightness-110 text-white transition-all transform group-hover:scale-105">
                        {isProcessingAI ? <div className="w-4 h-4 border-2 border-white/50 border-t-white rounded-full animate-spin" /> : <Wand2 size={20} />}
                    </div>
                    <span className="text-[10px] font-semibold text-white/90 drop-shadow-md">Magic</span>
                </button>

                <button 
                  onClick={handleReset}
                  className="flex flex-col items-center gap-1 group"
                  title="Reset All"
                >
                    <div className="w-10 h-10 bg-slate-900/60 backdrop-blur-md border border-white/10 rounded-full flex items-center justify-center shadow-lg hover:bg-red-500/80 text-white transition-all transform group-hover:scale-105">
                        <RefreshCw size={18} />
                    </div>
                    <span className="text-[10px] font-semibold text-white/90 drop-shadow-md">Reset</span>
                </button>
            </div>
        )}

        {isDrawing && !selectedId && (
            <div 
                ref={toolbarRef}
                className={`absolute flex items-center gap-2 p-2 bg-slate-900/90 backdrop-blur-md rounded-full border border-white/10 z-[60] shadow-2xl select-none animate-in slide-in-from-bottom-5 transition-all duration-75 ${isDraggingToolbar ? 'scale-[1.02] border-blue-500/50 cursor-grabbing' : 'hover:border-white/30'}`}
                style={{
                    left: toolbarPos.x !== null ? `${toolbarPos.x}px` : '50%',
                    top: toolbarPos.y !== null ? `${toolbarPos.y}px` : 'auto',
                    bottom: toolbarPos.y === null ? '24px' : 'auto',
                    transform: toolbarPos.x === null ? 'translateX(-50%)' : 'none',
                }}
            >
                 <div 
                    className="cursor-grab p-2 text-white/40 hover:text-white transition-colors active:cursor-grabbing"
                    onPointerDown={handleToolbarDragStart}
                 >
