                 <div className="w-[1px] h-6 bg-white/10 mx-1"></div>

                 <div className="flex gap-1 px-1">
                    <button 
                        onClick={() => setDrawingTool('pen')}
                        className={`p-2 rounded-full transition-all ${drawingTool === 'pen' ? 'bg-white text-black' : 'text-white hover:bg-white/10'}`}
                        title="Pen"
                    >
                        <Pen size={16} />
                    </button>
                    <button 
                        onClick={() => setDrawingTool('highlighter')}
                        className={`p-2 rounded-full transition-all ${drawingTool === 'highlighter' ? 'bg-white text-black' : 'text-white hover:bg-white/10'}`}
                        title="Highlighter"
                    >
                        <Highlighter size={16} />
                    </button>
                 </div>

                 <div className="w-[1px] h-6 bg-white/20 mx-1"></div>

                 <div className="flex gap-2 px-2">
                    {COLORS.map(color => (
                        <button
                            key={color}
                            className={`w-6 h-6 rounded-full border-2 transition-transform ${drawingColor === color ? 'border-white scale-110' : 'border-transparent hover:scale-105'}`}
                            style={{ backgroundColor: color }}
                            onClick={() => setDrawingColor(color)}
                        />
                    ))}
                 </div>

                 <div className="w-[1px] h-6 bg-white/20 mx-1"></div>

                 <div className="flex gap-2 px-2 items-center">
                    <button onClick={() => setDrawingSize(Math.max(2, drawingSize - 2))} className="p-1 hover:text-blue-400"><Circle size={8} fill="currentColor" /></button>
                    <span className="text-xs w-4 text-center tabular-nums font-medium">{drawingSize}</span>
                    <button onClick={() => setDrawingSize(Math.min(20, drawingSize + 2))} className="p-1 hover:text-blue-400"><Circle size={16} fill="currentColor" /></button>
                 </div>

                 <div className="w-[1px] h-6 bg-white/20 mx-1"></div>

                 <button 
                    onClick={() => {
                        setStrokes([]);
                        pushToHistory(layers, []);
                    }}
                    className="p-1.5 text-white/70 hover:text-red-400 transition-colors"
                    title="Clear Drawing"
                 >
                     <Trash2 size={16} />
                 </button>
            </div>
        )}
      </Editor>

      {selectedId && selectedLayer && (
        <FloatingToolbar
          layer={selectedLayer}
          containerRef={containerRef}
          onUpdate={updateLayer}
          onDelete={deleteLayer}
          onClose={() => setSelectedId(null)}
        />
      )}
    </div>
  );
}

import React, { useState, useRef, useEffect, useCallback } from 'react';
import { Upload, Plus, Download, Wand2, Type, Trash2, RefreshCw, Pen, Palette, Circle, Highlighter, Undo2, Redo2, GripHorizontal } from 'lucide-react';
import { Editor } from './components/Editor';
import { TextLayer, Stroke, FONT_FAMILY_MAP, COLORS } from './types';
import { generateSmartCaption } from './services/gemini';
import { FloatingToolbar } from './components/FloatingToolbar';

interface HistoryState {
  layers: TextLayer[];
  strokes: Stroke[];
}

export default function App() {
  const [images, setImages] = useState<string[]>([]);
  const [layers, setLayers] = useState<TextLayer[]>([]);
  const [strokes, setStrokes] = useState<Stroke[]>([]);
  const [selectedId, setSelectedId] = useState<string | null>(null);
  const [isProcessingAI, setIsProcessingAI] = useState(false);

  // History State
  const [history, setHistory] = useState<HistoryState[]>([]);
  const [historyIndex, setHistoryIndex] = useState(-1);

  // Drawing State
  const [isDrawing, setIsDrawing] = useState(false);
  const [drawingTool, setDrawingTool] = useState<'pen' | 'highlighter'>('pen');
  const [drawingColor, setDrawingColor] = useState('#EF4444');
  const [drawingSize, setDrawingSize] = useState(5);

  // Movable Drawing Toolbar State
  const [toolbarPos, setToolbarPos] = useState<{ x: number | null, y: number | null }>({ x: null, y: null });
  const [isDraggingToolbar, setIsDraggingToolbar] = useState(false);
  const toolbarRef = useRef<HTMLDivElement>(null);
  const dragOffset = useRef({ x: 0, y: 0 });

  const containerRef = useRef<HTMLDivElement>(null);

  // --- History Management ---

  const pushToHistory = useCallback((newLayers: TextLayer[], newStrokes: Stroke[]) => {
    setHistory(prev => {
      const newHistory = prev.slice(0, historyIndex + 1);
      const nextState = { layers: JSON.parse(JSON.stringify(newLayers)), strokes: JSON.parse(JSON.stringify(newStrokes)) };

      if (newHistory.length > 0) {
        const last = newHistory[newHistory.length - 1];
        if (JSON.stringify(last) === JSON.stringify(nextState)) return prev;
      }

      const updated = [...newHistory, nextState];
      if (updated.length > 50) updated.shift();
      return updated;
    });
    setHistoryIndex(prev => {
      const newIdx = prev + 1;
      return Math.min(newIdx, 49);
    });
  }, [historyIndex]);

  const undo = () => {
    if (historyIndex > 0) {
      const prevIdx = historyIndex - 1;
      const state = history[prevIdx];
      setLayers(state.layers);
      setStrokes(state.strokes);
      setHistoryIndex(prevIdx);
      setSelectedId(null);
    }
  };

  const redo = () => {
    if (historyIndex < history.length - 1) {
      const nextIdx = historyIndex + 1;
      const state = history[nextIdx];
      setLayers(state.layers);
      setStrokes(state.strokes);
      setHistoryIndex(nextIdx);
      setSelectedId(null);
    }
  };

  useEffect(() => {
    if (images.length > 0 && history.length === 0) {
      setHistory([{ layers: [], strokes: [] }]);
      setHistoryIndex(0);
    }
  }, [images, history.length]);

  // --- Drawing Toolbar Dragging Logic ---
  const handleToolbarDragStart = (e: React.PointerEvent) => {
    if (!toolbarRef.current) return;
    e.stopPropagation();

    const rect = toolbarRef.current.getBoundingClientRect();
    dragOffset.current = {
      x: e.clientX - rect.left,
      y: e.clientY - rect.top
    };

    setIsDraggingToolbar(true);
    // Use setPointerCapture to ensure move events are captured even if cursor leaves handle
    (e.currentTarget as HTMLElement).setPointerCapture(e.pointerId);
  };

  useEffect(() => {
    if (!isDraggingToolbar) return;

    const handlePointerMove = (e: PointerEvent) => {
      if (!containerRef.current || !toolbarRef.current) return;

      const containerRect = containerRef.current.getBoundingClientRect();
      const toolbarWidth = toolbarRef.current.offsetWidth;
      const toolbarHeight = toolbarRef.current.offsetHeight;

      // Calculate desired position relative to container
      let newX = e.clientX - containerRect.left - dragOffset.current.x;
      let newY = e.clientY - containerRect.top - dragOffset.current.y;

      // Strict clamping to container boundaries
      newX = Math.max(0, Math.min(newX, containerRect.width - toolbarWidth));
      newY = Math.max(0, Math.min(newY, containerRect.height - toolbarHeight));

      setToolbarPos({ x: newX, y: newY });
    };

    const handlePointerUp = (e: PointerEvent) => {
      setIsDraggingToolbar(false);
    };

    window.addEventListener('pointermove', handlePointerMove);
    window.addEventListener('pointerup', handlePointerUp);
    return () => {
      window.removeEventListener('pointermove', handlePointerMove);
      window.removeEventListener('pointerup', handlePointerUp);
    };
  }, [isDraggingToolbar]);

  // --- Actions ---

  const handleImageUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onload = (event) => {
        const result = event.target?.result as string;
        setImages(prev => {
          if (prev.length === 0) return [result];
          if (prev.length === 1) return [...prev, result];
          return [prev[0], result];
        });

        if (images.length === 0) {
            setLayers([]);
            setStrokes([]);
            setHistory([{ layers: [], strokes: [] }]);
            setHistoryIndex(0);
            setToolbarPos({ x: null, y: null });
        }
      };
      reader.readAsDataURL(file);
    }
  };

  const handleReset = () => {
    setImages([]);
    setLayers([]);
    setStrokes([]);
    setSelectedId(null);
    setIsDrawing(false);
    setHistory([]);
    setHistoryIndex(-1);
    setToolbarPos({ x: null, y: null });
  };

  const addTextLayer = (initialText = "Tap to edit") => {
    if (isDrawing) setIsDrawing(false);

    const newLayer: TextLayer = {
      id: crypto.randomUUID(),
      content: initialText,
      x: 0.5,
      y: 0.5,
      color: '#FFFFFF',
      backgroundColor: 'transparent',
      fontSize: 1.0,
      fontFamily: 'font-anton',
      rotation: 0,
    };
    const nextLayers = [...layers, newLayer];
    setLayers(nextLayers);
    setSelectedId(newLayer.id);
    pushToHistory(nextLayers, strokes);
  };

  const updateLayer = (id: string, updates: Partial<TextLayer>, skipHistory = false) => {
    const nextLayers = layers.map((layer) => (layer.id === id ? { ...layer, ...updates } : layer));
    setLayers(nextLayers);
    if (!skipHistory) {
      pushToHistory(nextLayers, strokes);
    }
  };

  const deleteLayer = (id: string) => {
    const nextLayers = layers.filter((l) => l.id !== id);
    setLayers(nextLayers);
    if (selectedId === id) setSelectedId(null);
    pushToHistory(nextLayers, strokes);
  };

  const handleAddStroke = (stroke: Stroke) => {
    const nextStrokes = [...strokes, stroke];
    setStrokes(nextStrokes);
    pushToHistory(layers, nextStrokes);
  };

  const handleSmartCaption = async () => {
    if (images.length === 0) return;
    setIsProcessingAI(true);
    try {
      const caption = await generateSmartCaption(images[0]);
      addTextLayer(caption);
    } catch (err) {
      alert("Failed to generate caption. Please check your API key or connection.");
    } finally {
      setIsProcessingAI(false);
    }
  };

  const loadImage = (src: string): Promise<HTMLImageElement> => {
    return new Promise((resolve, reject) => {
      const img = new Image();
      img.crossOrigin = "anonymous";
      img.onload = () => resolve(img);
      img.onerror = reject;
      img.src = src;
    });
  };

  const roundRect = (ctx: CanvasRenderingContext2D, x: number, y: number, width: number, height: number, radius: number) => {
    ctx.beginPath();
    ctx.moveTo(x + radius, y);
    ctx.lineTo(x + width - radius, y);
    ctx.quadraticCurveTo(x + width, y, x + width, y + radius);
    ctx.lineTo(x + width, y + height - radius);
    ctx.quadraticCurveTo(x + width, y + height, x + width - radius, y + height);
    ctx.lineTo(x + radius, y + height);
    ctx.quadraticCurveTo(x, y + height, x, y + height - radius);
    ctx.lineTo(x, y + radius);
    ctx.quadraticCurveTo(x, y, x + radius, y);
    ctx.closePath();
    ctx.fill();
  };

  const handleExport = async () => {
    if (images.length === 0) return;

    try {
        const canvas = document.createElement('canvas');
        const ctx = canvas.getContext('2d');
        if (!ctx) return;

        const loadedImages = await Promise.all(images.map(src => loadImage(src)));
        const img1 = loadedImages[0];

        let canvasWidth = img1.naturalWidth;
        const canvasHeight = img1.naturalHeight;

        let img2Specs: { img: HTMLImageElement, width: number, height: number, x: number } | null = null;

        if (loadedImages.length > 1) {
            const img2 = loadedImages[1];
            const scaleFactor = img1.naturalHeight / img2.naturalHeight;
            const scaledWidth = img2.naturalWidth * scaleFactor;

            img2Specs = {
                img: img2,
                width: scaledWidth,
                height: img1.naturalHeight,
                x: img1.naturalWidth
            };

            canvasWidth += scaledWidth;
        }

        canvas.width = canvasWidth;
        canvas.height = canvasHeight;

        ctx.drawImage(img1, 0, 0);
        if (img2Specs) {
            ctx.drawImage(img2Specs.img, img2Specs.x, 0, img2Specs.width, img2Specs.height);
        }

        ctx.lineCap = 'round';
        ctx.lineJoin = 'round';

        strokes.forEach(stroke => {
            if (stroke.points.length === 0) return;

            ctx.save();
            ctx.beginPath();
            ctx.strokeStyle = stroke.color;
            ctx.globalAlpha = stroke.opacity;
            const strokeScale = canvasWidth / (containerRef.current?.clientWidth || canvasWidth);
            ctx.lineWidth = stroke.size * strokeScale;

            const points = stroke.points;

            if (points.length < 3) {
                ctx.moveTo(points[0].x * canvasWidth, points[0].y * canvasHeight);
                for(let i=1; i<points.length; i++) {
                    ctx.lineTo(points[i].x * canvasWidth, points[i].y * canvasHeight);
                }
            } else {
                ctx.moveTo(points[0].x * canvasWidth, points[0].y * canvasHeight);
                let i;
                for (i = 1; i < points.length - 2; i++) {
                    const xc = (points[i].x + points[i + 1].x) / 2;
                    const yc = (points[i].y + points[i + 1].y) / 2;
                    ctx.quadraticCurveTo(
                        points[i].x * canvasWidth, 
                        points[i].y * canvasHeight, 
                        xc * canvasWidth, 
                        yc * canvasHeight
                    );
                }
                ctx.quadraticCurveTo(
                    points[i].x * canvasWidth, 
                    points[i].y * canvasHeight, 
                    points[i+1].x * canvasWidth, 
                    points[i+1].y * canvasHeight
                );
            }

            ctx.stroke();
            ctx.restore();
        });

        layers.forEach((layer) => {
            const fontSizePx = (canvasWidth / 20) * layer.fontSize;

            ctx.save();
            const x = layer.x * canvasWidth;
            const y = layer.y * canvasHeight;

            ctx.translate(x, y);
            ctx.rotate((layer.rotation * Math.PI) / 180);

            let fontFamily = FONT_FAMILY_MAP[layer.fontFamily] || 'sans-serif';
            fontFamily = fontFamily.replace(/"/g, ''); 

            ctx.font = `bold ${fontSizePx}px ${fontFamily}`;
            ctx.textAlign = 'center';
            ctx.textBaseline = 'middle';

            let lines = layer.content.split('\n');
            if (layer.maxWidth) {
                const maxPx = layer.maxWidth * canvasWidth;
                const wrappedLines: string[] = [];
                lines.forEach(paragraph => {
                    const words = paragraph.split(' ');
                    let currentLine = words[0];
                    for (let i = 1; i < words.length; i++) {
                        const word = words[i];
                        const width = ctx.measureText(currentLine + " " + word).width;
                        if (width < maxPx) {
                            currentLine += " " + word;
                        } else {
                            wrappedLines.push(currentLine);
                            currentLine = word;
                        }
                    }
                    wrappedLines.push(currentLine);
                });
                lines = wrappedLines;
            }

            const lineHeight = fontSizePx * 1.2;
            const totalHeight = lines.length * lineHeight;

            let maxLineWidth = 0;
            lines.forEach(line => {
                const metrics = ctx.measureText(line);
                if (metrics.width > maxLineWidth) maxLineWidth = metrics.width;
            });

            if (layer.backgroundColor !== 'transparent') {
                const paddingX = fontSizePx * 0.4;
                const paddingY = fontSizePx * 0.2;
                const bgWidth = maxLineWidth + (paddingX * 2);
                const bgHeight = totalHeight + (paddingY * 2);

                ctx.fillStyle = layer.backgroundColor;
                roundRect(
                    ctx, 
                    -bgWidth / 2, 
                    -bgHeight / 2, 
                    bgWidth, 
                    bgHeight, 
                    fontSizePx * 0.2
                );
            } else {
                ctx.shadowColor = 'rgba(0, 0, 0, 0.5)';
                ctx.shadowBlur = 4;
                ctx.shadowOffsetY = 2;
            }

            ctx.fillStyle = layer.color;
            if (layer.backgroundColor !== 'transparent') {
                 ctx.shadowColor = 'transparent';
            }

            let startY = -(totalHeight / 2) + (lineHeight / 2);
            lines.forEach((line, i) => {
                ctx.fillText(line, 0, startY + (i * lineHeight));
            });

            ctx.restore();
        });

        const link = document.createElement('a');
        link.download = `snaptext-${Date.now()}.png`;
        link.href = canvas.toDataURL('image/png');
        link.click();

    } catch (e) {
        console.error("Export failed", e);
        alert("Failed to export image.");
    }
  };

  const currentOpacity = drawingTool === 'highlighter' ? 0.45 : 1.0;
  const displayDrawingSize = drawingTool === 'highlighter' ? drawingSize * 3 : drawingSize;

  if (images.length === 0) {
    return (
      <div className="h-screen w-full flex flex-col items-center justify-center bg-slate-900 text-white p-6 relative overflow-hidden">
        <div className="absolute top-[-10%] left-[-10%] w-[40%] h-[40%] bg-purple-600 rounded-full blur-[120px] opacity-20"></div>
        <div className="absolute bottom-[-10%] right-[-10%] w-[40%] h-[40%] bg-blue-600 rounded-full blur-[120px] opacity-20"></div>

        <div className="z-10 text-center max-w-md">
          <div className="mb-6 flex justify-center">
            <div className="w-20 h-20 bg-gradient-to-tr from-purple-500 to-pink-500 rounded-2xl flex items-center justify-center shadow-lg transform rotate-3">
               <Type size={40} className="text-white" />
            </div>
          </div>
          <h1 className="text-4xl font-extrabold mb-4 tracking-tight">SnapText Editor</h1>
          <p className="text-slate-400 mb-8 text-lg">
            Add bold, beautiful text to your photos. Messenger-style editing with side-by-side support.
          </p>

          <label className="group relative inline-flex items-center justify-center px-8 py-4 text-lg font-bold text-white transition-all duration-200 bg-blue-600 font-pj rounded-full focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-blue-600 hover:bg-blue-500 cursor-pointer shadow-lg shadow-blue-500/30">
            <span className="absolute inset-0 transition-transform translate-x-1 translate-y-1 bg-blue-700 group-hover:translate-y-0 group-hover:translate-x-0 rounded-full"></span>
            <span className="relative flex items-center gap-2">
              <Upload size={24} />
              <span>Choose Photo</span>
            </span>
            <input type="file" accept="image/*" onChange={handleImageUpload} className="hidden" />
          </label>
        </div>
      </div>
    );
  }

  const selectedLayer = layers.find(l => l.id === selectedId);

  return (
    <div className="h-screen w-full flex flex-col bg-slate-950 text-white overflow-hidden relative">
      <header className="h-16 px-4 flex items-center justify-between border-b border-slate-800 bg-slate-900/50 backdrop-blur-md z-40">
        <div className="flex items-center gap-2 font-bold text-xl tracking-tight">
          <span className="text-blue-500">Snap</span>Text
        </div>

        <div className="flex items-center gap-2">
          <button 
            onClick={undo}
            disabled={historyIndex <= 0}
            className="p-2 text-slate-300 hover:text-white disabled:opacity-30 disabled:cursor-not-allowed transition-all"
            title="Undo"
