                    title="Clear Drawing"
                 >
                     <Trash2 size={16} />
                 </button>
            </div>
        )}
      </Editor>

      {selectedId && selectedLayer && (
        <FloatingToolbar
          layer={selectedLayer}
          containerRef={containerRef}
